ST.xhtml:p:
STC_CalcHorizontalTravel := 0.0;
IF i_from_stn > 0 AND i_to_stn > 0 AND i_from_stn <> i_to_stn THEN
  from_idx := i_from_stn - 100;
  to_idx   := i_to_stn - 100;
  IF from_idx >= 1 AND from_idx <= 25 AND to_idx >= 1 AND to_idx <= 25 THEN
    STC_CalcHorizontalTravel := INT_TO_REAL(i_move.Travel[from_idx].ToTime[to_idx]) / 10.0;
  END_IF;
END_IF;

STC_CalcTransferTime := 0.0;
IF i_from_stn > 0 AND i_from_stn <> i_to_stn THEN
  from_idx := i_from_stn - 100;
  to_idx   := i_to_stn - 100;
  IF from_idx >= 1 AND from_idx <= 25 AND to_idx >= 1 AND to_idx <= 25 THEN
    STC_CalcTransferTime :=
      INT_TO_REAL(i_move.LiftTime[from_idx]) / 10.0
      + INT_TO_REAL(i_move.Travel[from_idx].ToTime[to_idx]) / 10.0
      + INT_TO_REAL(i_move.SinkTime[to_idx]) / 10.0;
  END_IF;
END_IF;

IF NOT i_can_evade THEN
  TWA_CalcPriority := DINT#100000;
  RETURN;
END_IF;

IF i_phase = 3 THEN
  dist := ABS(i_x_pos - i_x_target);
  IF dist > 99999 THEN dist := 99999; END_IF;
  TWA_CalcPriority := DINT#200000 + (DINT#99999 - dist);
ELSIF i_phase = 1 THEN
  dist := ABS(i_x_pos - i_x_target);
  IF dist > 99999 THEN dist := 99999; END_IF;
  TWA_CalcPriority := DINT#100000 + (DINT#99999 - dist);
ELSE
  TWA_CalcPriority := 1;
END_IF;

(* Guard *)
IF i_trans < 1 OR i_trans > MAX_Transporters THEN
  RETURN;
END_IF;

(* Reset output *)
g_dep_idle_slot[i_trans].Count := 0;
si := 0;
cnt := g_task[i_trans].Count;

prev_end  := i_time_s;
(* G05: Use transporter's current station as first-slot anchor *)
prev_sink := g_transporter[i_trans].CurrentStation;

FOR qi := 1 TO MAX_Units DO
  IF qi > cnt THEN
    EXIT;
  END_IF;

  gap_start := prev_end;
  gap_end   := g_task[i_trans].Queue[qi].StartTime;

  (* Only create slot if there is a meaningful gap *)
  IF gap_end > gap_start + LINT#1 THEN
    si := si + 1;
    IF si <= DEP_MAX_IDLE_SLOTS THEN
      g_dep_idle_slot[i_trans].Slots[si].StartTime   := gap_start;
      g_dep_idle_slot[i_trans].Slots[si].EndTime     := gap_end;
      g_dep_idle_slot[i_trans].Slots[si].LiftStationTarget := prev_sink;
      g_dep_idle_slot[i_trans].Slots[si].SinkStationTarget := g_task[i_trans].Queue[qi].LiftStationTarget;
    END_IF;
  END_IF;

  prev_end  := g_task[i_trans].Queue[qi].FinishTime;
  prev_sink := g_task[i_trans].Queue[qi].SinkStationTarget;
END_FOR;

(* Final slot: after last task → open-ended *)
si := si + 1;
IF si <= DEP_MAX_IDLE_SLOTS THEN
  g_dep_idle_slot[i_trans].Slots[si].StartTime   := prev_end;
  g_dep_idle_slot[i_trans].Slots[si].EndTime     := HORIZON;
  g_dep_idle_slot[i_trans].Slots[si].LiftStationTarget := prev_sink;
  g_dep_idle_slot[i_trans].Slots[si].SinkStationTarget := 0;
END_IF;

g_dep_idle_slot[i_trans].Count := si;

g_dep_overlap.Count := 0;

(* G09: Clear full 0..200 domain first *)
FOR stn := 0 TO 200 DO
  g_dep_overlap.Flags[stn] := FALSE;
END_FOR;

FOR stn := MIN_StationIndex TO MAX_StationIndex DO
  cover_count := 0;

  FOR ti := 1 TO MAX_Transporters DO
    covered := FALSE;
    FOR ai := 1 TO 4 DO
      IF NOT covered THEN
        area := g_cfg[ti].TaskArea[ai];
        (* Station is covered if within lift OR sink range *)
        IF (area.MinLift > 0 AND stn >= area.MinLift AND stn <= area.MaxLift)
           OR (area.MinSink > 0 AND stn >= area.MinSink AND stn <= area.MaxSink) THEN
          covered := TRUE;
        END_IF;
      END_IF;
    END_FOR;
    IF covered THEN
      cover_count := cover_count + 1;
    END_IF;
  END_FOR;

  IF cover_count >= 2 THEN
    g_dep_overlap.Flags[stn] := TRUE;
    g_dep_overlap.Count := g_dep_overlap.Count + 1;
  ELSE
    g_dep_overlap.Flags[stn] := FALSE;
  END_IF;
END_FOR;

(* Initialize output *)
o_result.Fits         := FALSE;
o_result.DelayTime      := 0;
o_result.NeedExtraTime := 0;
o_result.TaskEndTime   := 0;
o_result.SlotIdx     := 0;
o_result.TransporterId     := i_trans_id;

IF i_trans_id < 1 OR i_trans_id > MAX_Transporters THEN
  RETURN;
END_IF;

task_dur   := i_task_end - i_task_start;
flex_up    := DINT_TO_REAL(i_max_time_s - i_calc_time_s);
IF flex_up < 0.0 THEN flex_up := 0.0; END_IF;
capped_flex := flex_up * i_flex_factor;

slot_cnt   := g_dep_idle_slot[i_trans_id].Count;
best_delay := 1.0E9;
best_slot  := 0;
found      := FALSE;
overflow_best_delay := 1.0E9;
overflow_best_slot  := 0;

tmp_move := g_move[i_trans_id];
FOR si := 1 TO DEP_MAX_IDLE_SLOTS DO
  IF si > slot_cnt THEN
    EXIT;
  END_IF;

  slot_start := g_dep_idle_slot[i_trans_id].Slots[si].StartTime;
  slot_end   := g_dep_idle_slot[i_trans_id].Slots[si].EndTime;

  (* ── Travel time: prev task sink → this lift ── *)
  from_stn := g_dep_idle_slot[i_trans_id].Slots[si].LiftStationTarget;
  travel_to := 0.0;
  IF from_stn > 0 AND from_stn <> i_lift_stn THEN
    travel_to := STC_CalcHorizontalTravel(i_from_stn := from_stn, i_to_stn := i_lift_stn, i_move := tmp_move);
  END_IF;

  (* ── Travel time: this sink → next task lift ── *)
  to_stn := g_dep_idle_slot[i_trans_id].Slots[si].SinkStationTarget;
  travel_from := 0.0;
  IF to_stn > 0 AND to_stn <> i_sink_stn THEN
    travel_from := STC_CalcHorizontalTravel(i_from_stn := i_sink_stn, i_to_stn := to_stn, i_move := tmp_move);
  END_IF;

  (* Earliest start = max(slot_start, task_start + shift) + travel_to + margin *)
  IF slot_start > (i_task_start + REAL_TO_LINT(i_shift_s)) THEN
    earliest := slot_start + REAL_TO_LINT(travel_to + i_margin_s);
  ELSE
    earliest := i_task_start + REAL_TO_LINT(i_shift_s + travel_to + i_margin_s);
  END_IF;

  (* Latest end = slot_end - travel_from - margin *)
  IF slot_end > LINT#9000000000 THEN
    (* Open-ended slot *)
    latest := LINT#9000000000;
  ELSE
    latest := slot_end - REAL_TO_LINT(travel_from + i_margin_s);
  END_IF;

  (* Check if task fits *)
  IF earliest + task_dur <= latest THEN
    delay := LINT_TO_REAL(earliest - i_task_start) - i_shift_s;
    IF delay < 0.0 THEN delay := 0.0; END_IF;

    (* Flex constraint: delay must not exceed capped flex *)
    IF delay <= capped_flex + i_margin_s THEN
      IF delay < best_delay THEN
        best_delay := delay;
        best_slot  := si;
        found      := TRUE;
      END_IF;
    ELSE
      (* Flex overflow — track separately for backward chaining *)
      IF delay < overflow_best_delay THEN
        overflow_best_delay := delay;
        overflow_best_slot  := si;
      END_IF;
    END_IF;
  END_IF;
END_FOR;

IF found THEN
  o_result.Fits      := TRUE;
  o_result.DelayTime   := REAL_TO_DINT(best_delay);
  o_result.SlotIdx  := best_slot;
  o_result.TaskEndTime := i_task_start + REAL_TO_LINT(i_shift_s + best_delay) + task_dur;
  o_result.NeedExtraTime := 0;
ELSE
  (* Report how much extra is needed for backward chaining *)
  o_result.Fits := FALSE;
  IF overflow_best_delay < 1.0E8 THEN
    (* Overflow slot found — report shortfall beyond capped flex *)
    o_result.DelayTime      := REAL_TO_DINT(overflow_best_delay);
    o_result.NeedExtraTime := REAL_TO_DINT(overflow_best_delay - capped_flex);
    IF o_result.NeedExtraTime < 0 THEN
      o_result.NeedExtraTime := 0;
    END_IF;
  ELSE
    (* No slot at all *)
    o_result.NeedExtraTime := 0;
  END_IF;
END_IF;

o_delay_s := 0.0;

(* Check if lift/sink are in overlap zone — G09: domain 0..200 *)
IF i_lift_stn >= 0 AND i_lift_stn <= 200 THEN
  lift_is_overlap := g_dep_overlap.Flags[i_lift_stn];
ELSE
  lift_is_overlap := FALSE;
END_IF;
IF i_sink_stn >= 0 AND i_sink_stn <= 200 THEN
  sink_is_overlap := g_dep_overlap.Flags[i_sink_stn];
ELSE
  sink_is_overlap := FALSE;
END_IF;

(* No overlap stations involved → no delay *)
IF NOT lift_is_overlap AND NOT sink_is_overlap THEN
  RETURN;
END_IF;

(* Iterative conflict resolution — max DEP_MAX_DELAY_ACTS rounds *)
FOR round := 1 TO DEP_MAX_DELAY_ACTS DO
  max_conf := 0.0;
  t_start  := i_task_start + REAL_TO_LINT(o_delay_s);
  t_end    := i_task_end + REAL_TO_LINT(o_delay_s);

  (* Check all tasks on OTHER transporters *)
  FOR ti := 1 TO MAX_Transporters DO
    IF ti <> i_trans_id THEN
      FOR qi := 1 TO MAX_Units DO
        IF qi > g_task[ti].Count THEN
          EXIT;
        END_IF;

        e_lift  := g_task[ti].Queue[qi].LiftStationTarget;
        e_sink  := g_task[ti].Queue[qi].SinkStationTarget;
        e_start := g_task[ti].Queue[qi].StartTime;
        e_end   := g_task[ti].Queue[qi].FinishTime;

        (* ★ G08: Zone membership — does existing task use ANY overlap station? *)
        has_ovlp := FALSE;
        IF e_lift >= 0 AND e_lift <= 200 THEN
          IF g_dep_overlap.Flags[e_lift] THEN
            has_ovlp := TRUE;
          END_IF;
        END_IF;
        IF NOT has_ovlp AND e_sink >= 0 AND e_sink <= 200 THEN
          IF g_dep_overlap.Flags[e_sink] THEN
            has_ovlp := TRUE;
          END_IF;
        END_IF;

        IF has_ovlp THEN
          (* Time overlap check: task overlaps with existing? *)
          IF t_start < (e_end + REAL_TO_LINT(i_margin_s)) AND t_end > (e_start - REAL_TO_LINT(i_margin_s)) THEN
            needed := LINT_TO_REAL(e_end - t_start) + i_margin_s;
            IF needed > max_conf THEN
              max_conf := needed;
            END_IF;
          END_IF;
        END_IF;

      END_FOR;  (* qi *)
    END_IF;
  END_FOR;  (* ti *)

  (* No conflict found → done *)
  IF max_conf <= 0.0 THEN
    EXIT;
  END_IF;
  o_delay_s := o_delay_s + max_conf;
END_FOR;  (* round *)

IF i_cmd = 1 THEN
  (* ── SNAPSHOT: globals → sandbox ── *)
  FOR ui := 1 TO MAX_Units DO
    g_dep_sandbox.Schedule[ui] := g_schedule[ui];
    g_dep_sandbox.Batches[ui]  := g_batch[ui];
    g_dep_sandbox.Programs[ui] := g_program[ui];
  END_FOR;
  FOR ti := 1 TO MAX_Transporters DO
    g_dep_sandbox.Tasks[ti] := g_task[ti];
  END_FOR;
  g_dep_sandbox.Valid := TRUE;

ELSIF i_cmd = 2 THEN
  (* ── RESTORE: sandbox → globals ── *)
  IF g_dep_sandbox.Valid THEN
    FOR ui := 1 TO MAX_Units DO
      g_schedule[ui] := g_dep_sandbox.Schedule[ui];
      g_batch[ui]  := g_dep_sandbox.Batches[ui];
      g_program[ui] := g_dep_sandbox.Programs[ui];
    END_FOR;
    FOR ti := 1 TO MAX_Transporters DO
      g_task[ti] := g_dep_sandbox.Tasks[ti];
    END_FOR;
  END_IF;

ELSIF i_cmd = 3 THEN
  (* ── CLEAR: invalidate sandbox ── *)
  g_dep_sandbox.Valid := FALSE;

END_IF;

IF NOT i_run THEN
  phase := 0;
  o_phase := 0;
  o_activated := FALSE;
  RETURN;
END_IF;

next_phase := phase;
o_activated := FALSE;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 0: STOPPED                                           *)
(* ════════════════════════════════════════════════════════════ *)
IF phase = 0 THEN
  next_phase := 1;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1: WAIT_STABLE                                       *)
(* Wait for TSK to be ready (phase >= 10000)                   *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1 THEN
  IF i_tsk_phase >= 10000 AND g_dep_stable THEN
    next_phase := 100;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 100: INIT — snapshot sandbox, find waiting batches    *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 100 THEN
  (* Snapshot globals → sandbox (backup for rollback) *)
  fb_sandbox(i_cmd := 1);

  (* Find waiting batches (state = NOT_PROCESSED) *)
  fb_collect_wait(i_mode := 1);
  waiting_cnt := fb_collect_wait.o_count;
  FOR ui := 1 TO waiting_cnt DO
    waiting_list[ui] := fb_collect_wait.o_list[ui];
  END_FOR;

  o_wait_cnt := waiting_cnt;
  g_dep_waiting_count := waiting_cnt;
  FOR ui := 1 TO waiting_cnt DO
    g_dep_waiting[ui] := waiting_list[ui];
  END_FOR;

  (* Build active batch list for rebuild phases *)
  fb_collect_all(i_mode := 0);
  batch_count := fb_collect_all.o_count;
  FOR ui := 1 TO batch_count DO
    batch_list[ui] := fb_collect_all.o_list[ui];
  END_FOR;

  IF waiting_cnt = 0 THEN
    (* No waiting batches → back to waiting *)
    fb_sandbox(i_cmd := 3);   (* clear sandbox *)
    next_phase := 1;
  ELSE
    cur_wait_idx := 1;
    next_phase := 150;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 150: SORT_WAITING — FIFO sort by start_time (G06)     *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 150 THEN
  (* Insertion sort waiting list by g_batch[unit].StartTime ascending *)
  FOR si := 2 TO waiting_cnt DO
    tmp_unit := waiting_list[si];
    tmp_key  := g_batch[tmp_unit].StartTime;
    ji := si - 1;
    WHILE ji >= 1 DO
      IF g_batch[waiting_list[ji]].StartTime > tmp_key THEN
        waiting_list[ji + 1] := waiting_list[ji];
        ji := ji - 1;
      ELSE
        EXIT;
      END_IF;
    END_WHILE;
    waiting_list[ji + 1] := tmp_unit;
  END_FOR;
  next_phase := 200;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 200: CALC_OVERLAP — compute overlap stations          *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 200 THEN
  fb_overlap();
  next_phase := 1000;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1000: BATCH_START — prepare current waiting batch     *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1000 THEN
  IF cur_wait_idx > waiting_cnt THEN
    (* All batches processed, none activated → back to waiting *)
    fb_sandbox(i_cmd := 2);   (* restore globals from snapshot *)
    fb_sandbox(i_cmd := 3);   (* clear sandbox *)
    next_phase := 1;
  ELSE
    cur_wait_unit := waiting_list[cur_wait_idx];
    fit_round := 0;
    sched_base_time := i_time_s;
    next_phase := 1010;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1010: CALC_SCHED — calculate waiting batch schedule   *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1010 THEN
  (* Find transporter for this batch based on its location *)
  fb_find(i_lift_stn := g_unit[cur_wait_unit].location, i_sink_stn := 0);
  sched_trans := fb_find.o_trans;
  IF sched_trans = 0 THEN sched_trans := 1; END_IF;

  (* Calculate schedule using (possibly shifted) base time *)
  fb_calc_sched(
    i_unit   := cur_wait_unit,
    i_trans  := sched_trans,
    i_time_s := sched_base_time
  );

  next_phase := 1020;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1020: CLEAR_TASKS — clear all task queues             *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1020 THEN
  fb_clear();
  create_idx := 1;
  next_phase := 1021;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1021: CREATE_TASKS — one batch per scan               *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1021 THEN
  IF create_idx <= batch_count THEN
    fb_create_tasks(i_unit := batch_list[create_idx]);
    create_idx := create_idx + 1;
    next_phase := 1021;   (* stay until all batches done *)
  ELSE
    next_phase := 1022;   (* all batches created → sort *)
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1022: SORT_TASKS — sort all queues by start_time      *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1022 THEN
  fb_sort(i_trans := 0);
  next_phase := 1023;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1023: SWAP_TASKS — swap same-station pairs            *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1023 THEN
  fb_swap_tasks();
  next_phase := 1030;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1030: EXTRACT_WAIT — extract waiting batch tasks      *)
(* Copy waiting batch's tasks to w_tasks[], remove from queues *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1030 THEN
  w_task_cnt := 0;

  FOR ti := 1 TO MAX_Transporters DO
    write_idx := 0;
    FOR qi := 1 TO g_task[ti].Count DO
      IF g_task[ti].Queue[qi].Unit = cur_wait_unit THEN
        (* Copy to waiting task array *)
        w_task_cnt := w_task_cnt + 1;
        IF w_task_cnt <= 30 THEN
          w_tasks[w_task_cnt] := g_task[ti].Queue[qi];
          w_trans[w_task_cnt] := ti;
        END_IF;
      ELSE
        (* Keep in queue — shift down *)
        write_idx := write_idx + 1;
        IF write_idx <> qi THEN
          g_task[ti].Queue[write_idx] := g_task[ti].Queue[qi];
        END_IF;
      END_IF;
    END_FOR;
    (* Clear remaining slots *)
    FOR qi := write_idx + 1 TO g_task[ti].Count DO
      g_task[ti].Queue[qi].Unit := 0;
    END_FOR;
    g_task[ti].Count := write_idx;
  END_FOR;

  next_phase := 1040;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1040: CALC_IDLE — calc idle slots for all transporters*)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1040 THEN
  FOR ti := 1 TO MAX_Transporters DO
    fb_idle_slots(i_trans := ti, i_time_s := i_time_s);
  END_FOR;
  cur_task_idx := 1;
  next_phase := 2000;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 2000: FIT_STAGE0 — inline idle-slot fit for pickup    *)
(* Matches JS departureScheduler.js stage 0 inline code:       *)
(*   earliestPickup = max(slot.start, currentTimeSec) + travel  *)
(*   NO margin in earliest (unlike fb_fit which adds margin).   *)
(*   Stage 0 delay NEVER triggers RECALC — only stage 1+ does. *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 2000 THEN
  loading_stn := g_unit[cur_wait_unit].location;

  (* Find first treatment station from schedule *)
  first_stn := 0;
  IF g_schedule[cur_wait_unit].StageCount >= 1 THEN
    first_stn := g_schedule[cur_wait_unit].Stages[1].station;
  END_IF;

  IF first_stn = 0 THEN
    next_phase := 9000;
  ELSIF loading_stn < 100 THEN
    (* ★ G07: Batch is on transporter — use transporter's current_station *)
    IF loading_stn >= 1 AND loading_stn <= MAX_Transporters THEN
      sched_trans := loading_stn;
      loading_stn := g_transporter[loading_stn].CurrentStation;
      IF loading_stn < 100 THEN
        next_phase := 9000;
      END_IF;
    ELSE
      next_phase := 9000;
    END_IF;
    IF next_phase <> 9000 THEN
      fb_find(i_lift_stn := loading_stn, i_sink_stn := first_stn);
      IF fb_find.o_trans > 0 THEN
        sched_trans := fb_find.o_trans;
      END_IF;
    END_IF;
  ELSE
    fb_find(i_lift_stn := loading_stn, i_sink_stn := first_stn);
    sched_trans := fb_find.o_trans;
    IF sched_trans = 0 THEN sched_trans := 1; END_IF;
  END_IF;

  IF next_phase <> 9000 THEN
    (* Calculate transfer time for pickup *)
    tmp_move := g_move[sched_trans];
    xfer_dur := STC_CalcTransferTime(i_from_stn := loading_stn, i_to_stn := first_stn, i_move := tmp_move);
    IF xfer_dur < 1.0 THEN xfer_dur := 1.0; END_IF;

    s0_task_dur := REAL_TO_LINT(xfer_dur);
    s0_slot_fitted := FALSE;
    s0_slot_cnt := g_dep_idle_slot[sched_trans].Count;
    stage0_delay := 0.0;

    (* ── Inline idle-slot scan (matches JS stage 0 logic) ── *)
    FOR s0_slot_si := 1 TO DEP_MAX_IDLE_SLOTS DO
      IF s0_slot_si > s0_slot_cnt THEN EXIT; END_IF;

      s0_slot_start := g_dep_idle_slot[sched_trans].Slots[s0_slot_si].StartTime;
      s0_slot_end   := g_dep_idle_slot[sched_trans].Slots[s0_slot_si].EndTime;
      IF s0_slot_end > i_time_s THEN
        (* Travel: prev task sink → pickup station (JS: travelToPickup) *)
        s0_from_stn := g_dep_idle_slot[sched_trans].Slots[s0_slot_si].LiftStationTarget;
        s0_travel_to := 0.0;
        IF s0_from_stn > 0 AND s0_from_stn <> loading_stn THEN
          s0_travel_to := STC_CalcHorizontalTravel(i_from_stn := s0_from_stn, i_to_stn := loading_stn, i_move := tmp_move);
        END_IF;

        (* JS: earliestPickup = max(slot.start, currentTimeSec) + travelToPickup *)
        IF s0_slot_start > i_time_s THEN
          s0_earliest := s0_slot_start + REAL_TO_LINT(s0_travel_to);
        ELSE
          s0_earliest := i_time_s + REAL_TO_LINT(s0_travel_to);
        END_IF;

        (* Travel: sink → next task lift (JS: travelFromSink) *)
        s0_to_stn := g_dep_idle_slot[sched_trans].Slots[s0_slot_si].SinkStationTarget;
        s0_travel_from := 0.0;
        IF s0_to_stn > 0 AND s0_to_stn <> first_stn THEN
          s0_travel_from := STC_CalcHorizontalTravel(i_from_stn := first_stn, i_to_stn := s0_to_stn, i_move := tmp_move);
        END_IF;

        (* JS: slotEnd = slot.nextTask ? slot.end - travelFromSink - conflictMargin : slot.end *)
        IF s0_to_stn > 0 THEN
          s0_slot_end := s0_slot_end - REAL_TO_LINT(s0_travel_from + CONFLICT_MARGIN_S);
        END_IF;

        (* ★ G10: Overlap check for stage 0 *)
        fb_ovlp_delay(
          i_lift_stn   := loading_stn,
          i_sink_stn   := first_stn,
          i_trans_id   := sched_trans,
          i_task_start := s0_earliest,
          i_task_end   := s0_earliest + s0_task_dur,
          i_margin_s   := CONFLICT_MARGIN_S
        );
        IF fb_ovlp_delay.o_delay_s > 0.0 THEN
          s0_earliest := s0_earliest + REAL_TO_LINT(fb_ovlp_delay.o_delay_s);
        END_IF;

        (* Does the task fit? *)
        IF s0_earliest + s0_task_dur <= s0_slot_end THEN
          (* JS: stage0Delay = effectiveStart - task.task_start_time *)
          stage0_delay := LINT_TO_REAL(s0_earliest - sched_base_time);
          IF stage0_delay < 0.0 THEN stage0_delay := 0.0; END_IF;

          (* maxInitialWaitS check *)
          IF stage0_delay <= MAX_INIT_WAIT_S THEN
            s0_slot_fitted := TRUE;

            (* ★ G11: Trim idle slot *)
            g_dep_idle_slot[sched_trans].Slots[s0_slot_si].StartTime :=
              s0_earliest + s0_task_dur;

            (* Record stage 0 delay — shift sched_base_time for stage 1+ *)
            IF stage0_delay > MARGIN_S THEN
              stage0_pending_delay := stage0_delay;
              sched_base_time := sched_base_time + REAL_TO_LINT(stage0_delay);
            ELSE
              stage0_pending_delay := 0.0;
            END_IF;

            EXIT;  (* Found a fitting slot *)
          END_IF;
        END_IF;
      END_IF;
    END_FOR;

    IF NOT s0_slot_fitted THEN
      (* Stage 0 doesn't fit any slot → REJECT *)
      next_phase := 9000;
    ELSE
      (* JS: stage 0 delay NEVER triggers RECALC alone.
         continue → proceed to stage 1+ tasks. *)
      IF w_task_cnt = 0 THEN
        next_phase := 8000;    (* No stage 1+ → ACTIVATE *)
      ELSE
        cur_task_idx := 1;
        next_phase := 2001;    (* Continue to stage 1+ fit *)
      END_IF;
    END_IF;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 2001: FIT_TASK — fit stage 1+ tasks one per tick      *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 2001 THEN
  IF cur_task_idx > w_task_cnt THEN
    (* All stage 1+ tasks fit → ACTIVATE.
       Stage 0 delay (if any) was already applied to sched_base_time
       in phase 2000. TSK will recalculate after activation. *)
    next_phase := 8000;
  ELSE
    (* Get current task data *)
    si := w_tasks[cur_task_idx].Stage;
    ti := w_trans[cur_task_idx];

    (* Overlap delay check *)
    fb_ovlp_delay(
      i_lift_stn   := w_tasks[cur_task_idx].LiftStationTarget,
      i_sink_stn   := w_tasks[cur_task_idx].SinkStationTarget,
      i_trans_id   := ti,
      i_task_start := w_tasks[cur_task_idx].StartTime,
      i_task_end   := w_tasks[cur_task_idx].FinishTime,
      i_margin_s   := CONFLICT_MARGIN_S
    );
    ovlp_delay_s := fb_ovlp_delay.o_delay_s;

    (* Idle-slot fit check *)
    fb_fit(
      i_lift_stn     := w_tasks[cur_task_idx].LiftStationTarget,
      i_sink_stn     := w_tasks[cur_task_idx].SinkStationTarget,
      i_trans_id     := ti,
      i_task_start   := w_tasks[cur_task_idx].StartTime,
      i_task_end     := w_tasks[cur_task_idx].FinishTime,
      i_shift_s      := ovlp_delay_s,
      i_calc_time_s  := w_tasks[cur_task_idx].CalcTime,
      i_max_time_s   := w_tasks[cur_task_idx].MaxTime,
      i_flex_factor  := FLEX_FACTOR,
      i_margin_s     := MARGIN_S
    );

    total_delay_s := ovlp_delay_s + DINT_TO_REAL(fb_fit.o_result.DelayTime);

    IF fb_fit.o_result.Fits THEN
      (* ★ G11: Trim idle slot after successful stage 1+ fit *)
      IF fb_fit.o_result.SlotIdx >= 1 AND fb_fit.o_result.SlotIdx <= DEP_MAX_IDLE_SLOTS THEN
        g_dep_idle_slot[ti].Slots[fb_fit.o_result.SlotIdx].StartTime :=
          fb_fit.o_result.TaskEndTime;
      END_IF;

      IF total_delay_s <= MARGIN_S THEN
        (* Fits with negligible delay → next task *)
        cur_task_idx := cur_task_idx + 1;
        next_phase := 2001;
      ELSE
        (* Delay needed → record and recalculate *)
        delay_stage  := si;
        delay_amount := total_delay_s;
        delay_target := 1;   (* program stage *)
        next_phase   := 3000;
      END_IF;
    ELSE
      (* ★ G02: Does not fit → try backward chaining *)
      IF fb_fit.o_result.NeedExtraTime <= 0 THEN
        (* No slot at all → reject *)
        next_phase := 9000;
      ELSE
        (* Walk backward through w_tasks, accumulate flex *)
        remaining_need := DINT_TO_REAL(fb_fit.o_result.NeedExtraTime);
        chain_delay_cnt := 0;
        chain_ok := FALSE;

        bk := cur_task_idx - 1;
        WHILE bk >= 1 AND remaining_need > MARGIN_S DO
          prev_flex_up := DINT_TO_REAL(w_tasks[bk].MaxTime - w_tasks[bk].CalcTime);
          IF prev_flex_up < 0.0 THEN prev_flex_up := 0.0; END_IF;
          prev_capped := prev_flex_up * FLEX_FACTOR;
          use_delay := prev_capped;
          IF use_delay > remaining_need THEN use_delay := remaining_need; END_IF;

          IF use_delay > MARGIN_S THEN
            chain_delay_cnt := chain_delay_cnt + 1;
            IF chain_delay_cnt <= 10 THEN
              chain_delays[chain_delay_cnt].Stage   := w_tasks[bk].Stage;
              chain_delays[chain_delay_cnt].DelayTime := REAL_TO_DINT(use_delay);
              IF w_tasks[bk].Stage = 0 THEN
                chain_delays[chain_delay_cnt].Target := 0;  (* batch *)
              ELSE
                chain_delays[chain_delay_cnt].Target := 1;  (* program stage *)
              END_IF;
              chain_delays[chain_delay_cnt].Valid := TRUE;
            END_IF;
            remaining_need := remaining_need - use_delay;
          END_IF;
          bk := bk - 1;
        END_WHILE;

        IF remaining_need <= MARGIN_S THEN chain_ok := TRUE; END_IF;

        IF chain_ok THEN
          (* Apply chain delays *)
          FOR ci := 1 TO chain_delay_cnt DO
            IF chain_delays[ci].Valid THEN
              IF chain_delays[ci].Target = 0 THEN
                (* Stage 0 / batch delay: shift base time *)
                sched_base_time := sched_base_time + DINT_TO_LINT(chain_delays[ci].DelayTime);
              ELSIF chain_delays[ci].Target = 1 THEN
                prog_idx := chain_delays[ci].Stage;
                IF prog_idx >= 1 AND prog_idx <= 30 THEN
                  old_cal := g_program[cur_wait_unit].Steps[prog_idx - 1].CalTime;
                  max_cal := g_program[cur_wait_unit].Steps[prog_idx - 1].MaxTime;
                  new_cal := old_cal + chain_delays[ci].DelayTime;
                  IF new_cal > max_cal AND max_cal > 0 THEN
                    new_cal := max_cal;
                  END_IF;
                  g_program[cur_wait_unit].Steps[prog_idx - 1].CalTime := new_cal;
                END_IF;
              END_IF;
            END_IF;
          END_FOR;

          (* Also apply the current task's total delay *)
          IF total_delay_s > MARGIN_S THEN
            delay_stage  := si;
            delay_amount := total_delay_s;
            delay_target := 1;
          END_IF;

          fit_round := fit_round + 1;
          IF fit_round > MAX_FIT_ROUNDS THEN
            next_phase := 9000;
          ELSE
            next_phase := 1010;  (* RECALC *)
          END_IF;
        ELSE
          (* Backward chaining insufficient → REJECT *)
          next_phase := 9000;
        END_IF;
      END_IF;
    END_IF;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 3000: APPLY_DELAY — write delay to program, recalc   *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 3000 THEN
  fit_round := fit_round + 1;
  IF fit_round > MAX_FIT_ROUNDS THEN
    next_phase := 9000;
  ELSE
    IF delay_target = 1 THEN
      (* Program stage delay: increase cal_time *)
      prog_idx := delay_stage;
      IF prog_idx >= 1 AND prog_idx <= 30 THEN
        old_cal := g_program[cur_wait_unit].Steps[prog_idx - 1].CalTime;
        max_cal := g_program[cur_wait_unit].Steps[prog_idx - 1].MaxTime;
        new_cal := old_cal + REAL_TO_DINT(delay_amount);
        IF new_cal > max_cal AND max_cal > 0 THEN
          new_cal := max_cal;
        END_IF;
        g_program[cur_wait_unit].Steps[prog_idx - 1].CalTime := new_cal;
      END_IF;
    END_IF;
    (* Recalculate: schedule → tasks → idle → fit *)
    next_phase := 1010;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 8000: ACTIVATE — commit changes to pending write      *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 8000 THEN
  (* Store pending write data *)
  FOR ui := 1 TO MAX_Units DO
    g_dep_pending.Programs[ui] := g_program[ui];
    g_dep_pending.Schedule[ui] := g_schedule[ui];
  END_FOR;
  g_dep_pending.BatchUnit  := cur_wait_unit;
  g_dep_pending.BatchStage := 0;    (* cur_stage = 0, JS: batch.Stage = 0 *)
  g_dep_pending.BatchState := 1;    (* NOT_PROCESSED → IN_PROCESS *)
  (* Stage 0 times — same naming as UDT_TreatmentProgramStepType: MinTime, MaxTime, CalTime *)
  g_dep_pending.BatchCalTime  := REAL_TO_DINT(stage0_pending_delay);
  g_dep_pending.BatchMinTime  := REAL_TO_DINT(stage0_pending_delay);
  g_dep_pending.BatchMaxTime  := REAL_TO_DINT(2.0 * stage0_pending_delay);
  IF g_dep_pending.BatchMaxTime < g_dep_pending.BatchCalTime THEN
    g_dep_pending.BatchMaxTime := g_dep_pending.BatchCalTime;
  END_IF;
  g_dep_pending.TimeStamp      := i_time_s;
  g_dep_pending.Valid        := TRUE;

  (* Restore globals from sandbox (undo DEP's temp changes) *)
  fb_sandbox(i_cmd := 2);
  fb_sandbox(i_cmd := 3);   (* clear sandbox *)

  g_dep_activated := TRUE;
  o_activated := TRUE;

  next_phase := 8010;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 8010: WAIT_SAVE — wait for TSK to process pending     *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 8010 THEN
  IF NOT g_dep_pending.Valid THEN
    (* TSK has processed the pending write *)
    next_phase := 8020;
  END_IF;
  (* Otherwise keep waiting *)

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 8020: END_DELAY — stabilization ticks                 *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 8020 THEN
  end_delay_cnt := 0;
  next_phase := 8021;

ELSIF phase >= 8021 AND phase <= 8120 THEN
  end_delay_cnt := end_delay_cnt + 1;
  IF end_delay_cnt >= END_DELAY_TICKS THEN
    next_phase := 8100;
  ELSE
    next_phase := phase + 1;
    IF next_phase > 8120 THEN
      next_phase := 8100;
    END_IF;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 8100: RESTART — back to WAIT_STABLE                   *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 8100 THEN
  g_dep_activated := FALSE;
  next_phase := 1;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 9000: REJECT — restore, try next batch                *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 9000 THEN
  (* Restore globals from sandbox (undo changes for this batch) *)
  fb_sandbox(i_cmd := 2);

  (* Try next waiting batch *)
  cur_wait_idx := cur_wait_idx + 1;
  IF cur_wait_idx > waiting_cnt THEN
    (* No more batches → back to waiting *)
    fb_sandbox(i_cmd := 3);
    next_phase := 1;
  ELSE
    (* Try next batch — re-snapshot is still valid *)
    next_phase := 1000;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* Unknown phase → reset                                       *)
(* ════════════════════════════════════════════════════════════ *)
ELSE
  next_phase := 1;
END_IF;

(* ── Phase assignment ── *)
phase := next_phase;
o_phase := phase;

(* --- Clear all stations --- *)
FOR i := MIN_StationIndex TO MAX_StationIndex DO
  g_station[i].TankId       := 0;
  g_station[i].IsInUse       := FALSE;
  g_station[i].XPosition    := 0;
  g_station[i].YPosition    := 0;
  g_station[i].ZPosition    := 0;
  g_station[i].DryWet          := 0;
  g_station[i].StationType     := 0;
  g_station[i].DrippingTime := 0;
  g_station[i].DeviceDelay  := 0;
END_FOR;

(* --- Clear all location tracking (transporters 1..MAX_Transporters + stations MIN..MAX) --- *)
FOR i := 1 TO MAX_StationIndex DO
  g_station_loc[i].UnitId     := 0;
  g_station_loc[i].ChangeTime := 0;
END_FOR;
g_station_count := 0;

(* --- Clear all transporter configs --- *)
FOR i := 1 TO MAX_Transporters DO
  g_cfg[i].DrivePosMin   := 0;
  g_cfg[i].DrivePosMax   := 0;
  g_cfg[i].YMinDriveLimit   := 0;
  g_cfg[i].YMaxDriveLimit   := 0;
  g_cfg[i].CollisionWidth    := 0;
  g_cfg[i].AvoidanceWidth    := 0;
  g_cfg[i].Acceleration_X     := 0;
  g_cfg[i].Deceleration_X     := 0;
  g_cfg[i].SpeedMax_X    := 0;
  g_cfg[i].ZPosDown    := 0;
  g_cfg[i].ZPosSlowUp := 0;
  g_cfg[i].ZPosSlowDown := 0;
  g_cfg[i].ZPosSlowEnd := 0;
  g_cfg[i].SpeedLiftSlow_Z   := 0;
  g_cfg[i].SpeedLiftFast_Z   := 0;
  g_cfg[i].DripTrayDelay  := 0;
  FOR j := 1 TO 4 DO
    g_cfg[i].TaskArea[j].MinLift := 0;
    g_cfg[i].TaskArea[j].MaxLift := 0;
    g_cfg[i].TaskArea[j].MinSink := 0;
    g_cfg[i].TaskArea[j].MaxSink := 0;
  END_FOR;
END_FOR;

(* --- Clear avoid status --- *)
FOR i := MIN_StationIndex TO MAX_StationIndex DO
  g_avoid_status[i] := 0;
END_FOR;

(* --- Clear all transporter states --- *)
FOR i := 1 TO MAX_Transporters DO
  g_transporter[i].IsActive          := FALSE;
  g_transporter[i].Status          := 0;
  g_transporter[i].Phase           := 0;
  g_transporter[i].TaskId         := 0;
  g_sim_trans[i].RunningTaskId := 0;
  g_transporter[i].LiftStationTarget    := 0;
  g_transporter[i].SinkStationTarget    := 0;
  g_sim_trans[i].TreatmentTime  := 0;
  g_sim_trans[i].LiftDeviceDelay := 0;
  g_sim_trans[i].SinkDeviceDelay := 0;
  g_transporter[i].DrippingTime   := 0;
  g_transporter[i].TaskRemainingTime  := 0;
  g_transporter[i].CurrentStation := 0;
  g_transporter[i].XFinalTarget  := 0;
  g_transporter[i].XDriveTarget  := 0;
  g_transporter[i].YFinalTarget  := 0;
  g_transporter[i].YDriveTarget  := 0;
  g_transporter[i].XPosition            := 0;
  g_transporter[i].YPosition            := 0;
  g_transporter[i].ZPosition            := 0;
  g_sim_trans[i].XVelocity           := 0;
  g_sim_trans[i].ZStage         := 0;
  g_sim_trans[i].ZTimer       := 0.0;
  g_transporter[i].XMinDriveLimit     := 0;
  g_transporter[i].XMaxDriveLimit     := 0;
END_FOR;

(* --- Clear all units --- *)
FOR i := 1 TO MAX_Units DO
  g_unit[i].location := 0;
  g_unit[i].Status   := 0;
  g_unit[i].Target   := 0;
END_FOR;

(* --- Clear NTT destinations --- *)
FOR i := 1 TO MAX_Transporters DO
  FOR j := 1 TO 8 DO
    g_ntt[i].Target[j].StationCount := 0;
    g_ntt[i].Target[j].FallbackCount := 0;
    FOR k := 1 TO MAX_STATIONS_PER_STEP DO
      g_ntt[i].Target[j].Stations[k] := 0;
      g_ntt[i].Target[j].FallbackStations[k] := 0;
    END_FOR;
  END_FOR;
END_FOR;

(* --- Clear all batches --- *)
FOR i := 1 TO MAX_Units DO
  g_batch[i].BatchCode  := 0;
  g_batch[i].State       := 0;
  g_batch[i].ProgId     := 0;
  g_batch[i].CurStage   := 0;
  g_batch[i].MinTime    := 0;
  g_batch[i].MaxTime    := 0;
  g_batch[i].CalTime    := 0;
  g_batch[i].StartTime  := LINT#0;
END_FOR;

(* --- Clear all treatment programs --- *)
FOR i := 1 TO MAX_Units DO
  g_program[i].ProgramId := 0;
  g_program[i].ProgramName := '';
  g_program[i].StepCount := 0;
  FOR j := 0 TO 30 DO
    FOR k := 0 TO 4 DO
      g_program[i].Steps[j].Stations[k] := 0;
    END_FOR;
    g_program[i].Steps[j].StationCount := 0;
    g_program[i].Steps[j].MinTime := 0;
    g_program[i].Steps[j].MaxTime := 0;
    g_program[i].Steps[j].CalTime := 0;
  END_FOR;
END_FOR;

(* --- Clear all schedules (g_schedule) --- *)
FOR i := 1 TO MAX_Units DO
  g_schedule[i].StageCount := 0;
  FOR j := 1 TO 30 DO
    g_schedule[i].Stages[j].station       := 0;
    g_schedule[i].Stages[j].EntryTime    := 0;
    g_schedule[i].Stages[j].ExitTime     := 0;
    g_schedule[i].Stages[j].MinTime      := 0;
    g_schedule[i].Stages[j].CalcTime     := 0;
    g_schedule[i].Stages[j].MaxTime      := 0;
    g_schedule[i].Stages[j].TransferTime := 0;
  END_FOR;
END_FOR;

(* --- Clear all task queues (g_task) --- *)
FOR i := 1 TO MAX_Transporters DO
  g_task[i].Count := 0;
  FOR j := 1 TO 60 DO
    g_task[i].Queue[j].Unit         := 0;
    g_task[i].Queue[j].Stage        := 0;
    g_task[i].Queue[j].LiftStationTarget := 0;
    g_task[i].Queue[j].SinkStationTarget := 0;
    g_task[i].Queue[j].StartTime   := 0;
    g_task[i].Queue[j].FinishTime  := 0;
    g_task[i].Queue[j].CalcTime    := 0;
    g_task[i].Queue[j].MinTime     := 0;
    g_task[i].Queue[j].MaxTime     := 0;
  END_FOR;
END_FOR;

(* --- Clear departure sandbox and pending write --- *)
g_dep_sandbox.Valid := FALSE;
g_dep_pending.Valid := FALSE;
g_dep_pending.BatchUnit  := 0;
g_dep_pending.BatchStage := 0;
g_dep_pending.BatchState := 0;

(* --- Clear departure scheduler state (previously missing) --- *)
g_dep_activated     := FALSE;
g_dep_stable        := FALSE;
g_dep_waiting_count := 0;
FOR i := 1 TO 5 DO
  g_dep_waiting[i] := 0;
END_FOR;

IF NOT i_run THEN
  RETURN;
END_IF;

FOR i := 1 TO MAX_Transporters DO
  IF g_transporter[i].IsActive THEN

  (* ── Phase 0 → 1: Accept new task ───────────────────────── *)
  IF (g_transporter[i].Phase = 0)
     AND (g_transporter[i].TaskId <> g_sim_trans[i].RunningTaskId) THEN
    g_sim_trans[i].RunningTaskId := g_transporter[i].TaskId;
    lookup(station_number := g_transporter[i].LiftStationTarget);
    g_transporter[i].XFinalTarget := lookup.x_mm;
    g_transporter[i].Phase := 1;
    g_transporter[i].Status := 4;  (* auto_run *)
    g_sim_trans[i].ZStage := 0;
    g_sim_trans[i].ZTimer := 0.0;

  (* ── Phase 1: Drive X towards lift station ──────────────── *)
  ELSIF g_transporter[i].Phase = 1 THEN
    tmp_x  := g_transporter[i].XPosition;
    tmp_vx := g_sim_trans[i].XVelocity;
    IF i = 1 THEN
      fb_x1(
        delta_t  := 0.02,
        x_target := g_transporter[i].XFinalTarget,
        x_min    := g_transporter[i].XMinDriveLimit,
        x_max    := g_transporter[i].XMaxDriveLimit,
        v_max    := g_cfg[i].SpeedMax_X,
        t_acc    := g_cfg[i].Acceleration_X,
        t_dec    := g_cfg[i].Deceleration_X,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x1.arrived;
    ELSIF i = 2 THEN
      fb_x2(
        delta_t  := 0.02,
        x_target := g_transporter[i].XFinalTarget,
        x_min    := g_transporter[i].XMinDriveLimit,
        x_max    := g_transporter[i].XMaxDriveLimit,
        v_max    := g_cfg[i].SpeedMax_X,
        t_acc    := g_cfg[i].Acceleration_X,
        t_dec    := g_cfg[i].Deceleration_X,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x2.arrived;
    ELSIF i = 3 THEN
      fb_x3(
        delta_t  := 0.02,
        x_target := g_transporter[i].XFinalTarget,
        x_min    := g_transporter[i].XMinDriveLimit,
        x_max    := g_transporter[i].XMaxDriveLimit,
        v_max    := g_cfg[i].SpeedMax_X,
        t_acc    := g_cfg[i].Acceleration_X,
        t_dec    := g_cfg[i].Deceleration_X,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x3.arrived;
    END_IF;
    g_transporter[i].XPosition  := tmp_x;
    g_sim_trans[i].XVelocity := tmp_vx;

    (* Only transition when actually at station, not just at drive limit *)
    at_station := arrived_x
                  AND (ABS(g_transporter[i].XPosition - g_transporter[i].XFinalTarget) <= 6);
    IF at_station THEN
      g_transporter[i].CurrentStation := g_transporter[i].LiftStationTarget;

      (* ── Wait for treatment time before lifting ──────────────
         If the unit at the lift station is IN_PROCESS and its
         treatment cal_time has not yet elapsed, stay at station
         and do NOT begin the lift sequence. *)
      can_lift := TRUE;
      lift_uid := g_station_loc[g_transporter[i].LiftStationTarget].UnitId;
      IF lift_uid >= 1 AND lift_uid <= MAX_Units THEN
        IF g_batch[lift_uid].State = IN_PROCESS
           AND g_batch[lift_uid].CurStage >= 1
           AND g_batch[lift_uid].CurStage <= MAX_STEPS_PER_PROGRAM THEN
          treat_cal := g_program[lift_uid].Steps[g_batch[lift_uid].CurStage - 1].CalTime;
          IF treat_cal > 0 THEN
            treat_elapsed := g_time_s - g_station_loc[g_transporter[i].LiftStationTarget].ChangeTime;
            IF treat_elapsed < DINT_TO_LINT(treat_cal) THEN
              can_lift := FALSE;
            END_IF;
          END_IF;
        END_IF;
      END_IF;

      IF can_lift THEN
      lookup(station_number := g_transporter[i].LiftStationTarget);
      device_delay := lookup.device_delay_s;
      drop_time    := lookup.dropping_time_s;
      g_sim_trans[i].ZTimer := device_delay + drop_time;
      g_sim_trans[i].ZStage := 1;
      g_transporter[i].Phase := 2;

      (* ── Emit LIFT event (msg_type=2) ── *)
      evt_unit := g_station_loc[g_transporter[i].LiftStationTarget].UnitId;
      IF NOT g_event_pending_valid AND evt_unit >= 1 THEN
        g_event_pending.MsgType := 2;
        g_event_pending.TsHi := LINT_TO_INT(g_time_s / LINT#65536);
        g_event_pending.TsLo := LINT_TO_INT(g_time_s MOD LINT#65536);
        g_event_pending.Payload[1]  := i;
        g_event_pending.Payload[2]  := evt_unit;
        g_event_pending.Payload[3]  := g_transporter[i].LiftStationTarget;
        g_event_pending.Payload[4]  := g_batch[evt_unit].BatchCode;
        g_event_pending.Payload[5]  := g_batch[evt_unit].State;
        g_event_pending.Payload[6]  := g_batch[evt_unit].ProgId;
        g_event_pending.Payload[7]  := g_batch[evt_unit].CurStage;
        evt_diff := g_time_s - g_station_loc[g_transporter[i].LiftStationTarget].ChangeTime;
        IF evt_diff > LINT#32000 THEN
          g_event_pending.Payload[8] := 32000;
        ELSE
          g_event_pending.Payload[8] := LINT_TO_INT(evt_diff);
        END_IF;
        g_event_pending.Payload[9]  := DINT_TO_INT(g_sim_trans[i].TreatmentTime);
        g_event_pending.Payload[10] := DINT_TO_INT(g_sim_trans[i].MinTime);
        g_event_pending.Payload[11] := DINT_TO_INT(g_sim_trans[i].MaxTime);
        g_event_pending.Payload[12] := 0;
        g_event_pending_valid := TRUE;
      END_IF;

      (* Unit moves from lift station → transporter *)
      pick_unit_id := g_station_loc[g_transporter[i].LiftStationTarget].UnitId;
      IF pick_unit_id >= 1 THEN
        IF i = 1 THEN
          upd_loc1(i_unit := pick_unit_id, i_location := i);
        ELSIF i = 2 THEN
          upd_loc2(i_unit := pick_unit_id, i_location := i);
        ELSIF i = 3 THEN
          upd_loc3(i_unit := pick_unit_id, i_location := i);
        END_IF;
      END_IF;
      END_IF;  (* can_lift *)
    END_IF;
    (* If arrived_x but not at_station → at drive limit, wait for clearance *)

  (* ── Phase 2: Lift Z at lift station ────────────────────── *)
  ELSIF g_transporter[i].Phase = 2 THEN
    lookup(station_number := g_transporter[i].LiftStationTarget);
    station_kind := lookup.skind;
    tmp_z  := g_transporter[i].ZPosition;
    tmp_zs := g_sim_trans[i].ZStage;
    tmp_zt := g_sim_trans[i].ZTimer;
    IF i = 1 THEN
      fb_z1(
        delta_t       := 0.02,
        station_kind  := station_kind,
        ZPosDown        := g_cfg[i].ZPosDown,
        ZPosUp          := 0,
        ZPosSlowUp      := g_cfg[i].ZPosSlowUp,
        ZPosSlowDown    := g_cfg[i].ZPosSlowDown,
        ZPosSlowEnd     := g_cfg[i].ZPosSlowEnd,
        SpeedLiftSlow_Z := g_cfg[i].SpeedLiftSlow_Z,
        SpeedLiftFast_Z := g_cfg[i].SpeedLiftFast_Z,
        DripTrayDelay   := g_cfg[i].DripTrayDelay,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z1.done;
    ELSIF i = 2 THEN
      fb_z2(
        delta_t       := 0.02,
        station_kind  := station_kind,
        ZPosDown        := g_cfg[i].ZPosDown,
        ZPosUp          := 0,
        ZPosSlowUp      := g_cfg[i].ZPosSlowUp,
        ZPosSlowDown    := g_cfg[i].ZPosSlowDown,
        ZPosSlowEnd     := g_cfg[i].ZPosSlowEnd,
        SpeedLiftSlow_Z := g_cfg[i].SpeedLiftSlow_Z,
        SpeedLiftFast_Z := g_cfg[i].SpeedLiftFast_Z,
        DripTrayDelay   := g_cfg[i].DripTrayDelay,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z2.done;
    ELSIF i = 3 THEN
      fb_z3(
        delta_t       := 0.02,
        station_kind  := station_kind,
        ZPosDown        := g_cfg[i].ZPosDown,
        ZPosUp          := 0,
        ZPosSlowUp      := g_cfg[i].ZPosSlowUp,
        ZPosSlowDown    := g_cfg[i].ZPosSlowDown,
        ZPosSlowEnd     := g_cfg[i].ZPosSlowEnd,
        SpeedLiftSlow_Z := g_cfg[i].SpeedLiftSlow_Z,
        SpeedLiftFast_Z := g_cfg[i].SpeedLiftFast_Z,
        DripTrayDelay   := g_cfg[i].DripTrayDelay,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z3.done;
    END_IF;
    g_transporter[i].ZPosition      := tmp_z;
    g_sim_trans[i].ZStage   := tmp_zs;
    g_sim_trans[i].ZTimer := tmp_zt;
    IF arrived_z THEN
      lookup(station_number := g_transporter[i].SinkStationTarget);
      g_transporter[i].XFinalTarget := lookup.x_mm;
      g_transporter[i].Phase := 3;
    END_IF;

  (* ── Phase 3: Drive X towards sink station ─────────────── *)
  ELSIF g_transporter[i].Phase = 3 THEN
    tmp_x  := g_transporter[i].XPosition;
    tmp_vx := g_sim_trans[i].XVelocity;
    IF i = 1 THEN
      fb_x1(
        delta_t  := 0.02,
        x_target := g_transporter[i].XFinalTarget,
        x_min    := g_transporter[i].XMinDriveLimit,
        x_max    := g_transporter[i].XMaxDriveLimit,
        v_max    := g_cfg[i].SpeedMax_X,
        t_acc    := g_cfg[i].Acceleration_X,
        t_dec    := g_cfg[i].Deceleration_X,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x1.arrived;
    ELSIF i = 2 THEN
      fb_x2(
        delta_t  := 0.02,
        x_target := g_transporter[i].XFinalTarget,
        x_min    := g_transporter[i].XMinDriveLimit,
        x_max    := g_transporter[i].XMaxDriveLimit,
        v_max    := g_cfg[i].SpeedMax_X,
        t_acc    := g_cfg[i].Acceleration_X,
        t_dec    := g_cfg[i].Deceleration_X,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x2.arrived;
    ELSIF i = 3 THEN
      fb_x3(
        delta_t  := 0.02,
        x_target := g_transporter[i].XFinalTarget,
        x_min    := g_transporter[i].XMinDriveLimit,
        x_max    := g_transporter[i].XMaxDriveLimit,
        v_max    := g_cfg[i].SpeedMax_X,
        t_acc    := g_cfg[i].Acceleration_X,
        t_dec    := g_cfg[i].Deceleration_X,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x3.arrived;
    END_IF;
    g_transporter[i].XPosition  := tmp_x;
    g_sim_trans[i].XVelocity := tmp_vx;

    (* Only transition when actually at station, not just at drive limit *)
    at_station := arrived_x
                  AND (ABS(g_transporter[i].XPosition - g_transporter[i].XFinalTarget) <= 6);
    IF at_station THEN
      g_transporter[i].CurrentStation := g_transporter[i].SinkStationTarget;
      lookup(station_number := g_transporter[i].SinkStationTarget);
      device_delay := lookup.device_delay_s;
      g_sim_trans[i].ZTimer := device_delay + INT_TO_REAL(g_cfg[i].DripTrayDelay) / 10.0;
      g_sim_trans[i].ZStage := 6;
      g_transporter[i].Phase := 4;
    END_IF;
    (* If arrived_x but not at_station → at drive limit, wait for clearance *)

  (* ── Phase 4: Sink Z at sink station ───────────────────── *)
  ELSIF g_transporter[i].Phase = 4 THEN
    lookup(station_number := g_transporter[i].SinkStationTarget);
    station_kind := lookup.skind;
    tmp_z  := g_transporter[i].ZPosition;
    tmp_zs := g_sim_trans[i].ZStage;
    tmp_zt := g_sim_trans[i].ZTimer;
    IF i = 1 THEN
      fb_z1(
        delta_t       := 0.02,
        station_kind  := station_kind,
        ZPosDown        := g_cfg[i].ZPosDown,
        ZPosUp          := 0,
        ZPosSlowUp      := g_cfg[i].ZPosSlowUp,
        ZPosSlowDown    := g_cfg[i].ZPosSlowDown,
        ZPosSlowEnd     := g_cfg[i].ZPosSlowEnd,
        SpeedLiftSlow_Z := g_cfg[i].SpeedLiftSlow_Z,
        SpeedLiftFast_Z := g_cfg[i].SpeedLiftFast_Z,
        DripTrayDelay   := g_cfg[i].DripTrayDelay,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z1.done;
    ELSIF i = 2 THEN
      fb_z2(
        delta_t       := 0.02,
        station_kind  := station_kind,
        ZPosDown        := g_cfg[i].ZPosDown,
        ZPosUp          := 0,
        ZPosSlowUp      := g_cfg[i].ZPosSlowUp,
        ZPosSlowDown    := g_cfg[i].ZPosSlowDown,
        ZPosSlowEnd     := g_cfg[i].ZPosSlowEnd,
        SpeedLiftSlow_Z := g_cfg[i].SpeedLiftSlow_Z,
        SpeedLiftFast_Z := g_cfg[i].SpeedLiftFast_Z,
        DripTrayDelay   := g_cfg[i].DripTrayDelay,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z2.done;
    ELSIF i = 3 THEN
      fb_z3(
        delta_t       := 0.02,
        station_kind  := station_kind,
        ZPosDown        := g_cfg[i].ZPosDown,
        ZPosUp          := 0,
        ZPosSlowUp      := g_cfg[i].ZPosSlowUp,
        ZPosSlowDown    := g_cfg[i].ZPosSlowDown,
        ZPosSlowEnd     := g_cfg[i].ZPosSlowEnd,
        SpeedLiftSlow_Z := g_cfg[i].SpeedLiftSlow_Z,
        SpeedLiftFast_Z := g_cfg[i].SpeedLiftFast_Z,
        DripTrayDelay   := g_cfg[i].DripTrayDelay,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z3.done;
    END_IF;
    g_transporter[i].ZPosition      := tmp_z;
    g_sim_trans[i].ZStage   := tmp_zs;
    g_sim_trans[i].ZTimer := tmp_zt;
    IF arrived_z THEN
      (* Unit moves from transporter → sink station *)
      sink_unit_id := g_station_loc[i].UnitId;
      IF sink_unit_id >= 1 THEN
        IF i = 1 THEN
          upd_loc1(i_unit := sink_unit_id, i_location := g_transporter[i].SinkStationTarget);
        ELSIF i = 2 THEN
          upd_loc2(i_unit := sink_unit_id, i_location := g_transporter[i].SinkStationTarget);
        ELSIF i = 3 THEN
          upd_loc3(i_unit := sink_unit_id, i_location := g_transporter[i].SinkStationTarget);
        END_IF;
      END_IF;

      g_transporter[i].Phase := 0;
      g_transporter[i].Status := 3;  (* auto_idle *)

    END_IF;
  END_IF;  (* ELSIF chain: phases 0→1→2→3→4 *)

  (* ── Phase 0 idle: drive back inside limits if outside ────── *)
  IF g_transporter[i].Phase = 0 THEN
    tmp_x  := g_transporter[i].XPosition;
    tmp_vx := g_sim_trans[i].XVelocity;
    (* Use current position as target — XMotion will clamp to nearest limit if outside *)
    IF i = 1 THEN
      fb_x1(
        delta_t  := 0.02,
        x_target := tmp_x,
        x_min    := g_transporter[i].XMinDriveLimit,
        x_max    := g_transporter[i].XMaxDriveLimit,
        v_max    := g_cfg[i].SpeedMax_X,
        t_acc    := g_cfg[i].Acceleration_X,
        t_dec    := g_cfg[i].Deceleration_X,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
    ELSIF i = 2 THEN
      fb_x2(
        delta_t  := 0.02,
        x_target := tmp_x,
        x_min    := g_transporter[i].XMinDriveLimit,
        x_max    := g_transporter[i].XMaxDriveLimit,
        v_max    := g_cfg[i].SpeedMax_X,
        t_acc    := g_cfg[i].Acceleration_X,
        t_dec    := g_cfg[i].Deceleration_X,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
    ELSIF i = 3 THEN
      fb_x3(
        delta_t  := 0.02,
        x_target := tmp_x,
        x_min    := g_transporter[i].XMinDriveLimit,
        x_max    := g_transporter[i].XMaxDriveLimit,
        v_max    := g_cfg[i].SpeedMax_X,
        t_acc    := g_cfg[i].Acceleration_X,
        t_dec    := g_cfg[i].Deceleration_X,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
    END_IF;
    g_transporter[i].XPosition  := tmp_x;
    g_sim_trans[i].XVelocity := tmp_vx;
  END_IF;

  (* ── Nearest station tracking ──────────────────────────── *)
  min_dist := 999999999;
  nearest_num := g_transporter[i].CurrentStation;
  FOR idx := MIN_StationIndex TO MAX_StationIndex DO
    IF g_station[idx].TankId <> 0 THEN
      dx := g_station[idx].XPosition - g_transporter[i].XPosition;
      IF ABS(dx) < min_dist THEN
        min_dist := ABS(dx);
        nearest_num := idx;
      END_IF;
    END_IF;
  END_FOR;
  g_transporter[i].CurrentStation := nearest_num;

  (* ── Measure move times (one instance per transporter) ──── *)
  IF i = 1 THEN
    tm1(t_id := 1, phase := g_transporter[1].Phase, delta_t := 0.02,
        vel_x := g_sim_trans[1].XVelocity, z_stage := g_sim_trans[1].ZStage,
        lift_stn := g_transporter[1].LiftStationTarget,
        sink_stn := g_transporter[1].SinkStationTarget,
        from_stn := g_transporter[1].CurrentStation);
  ELSIF i = 2 THEN
    tm2(t_id := 2, phase := g_transporter[2].Phase, delta_t := 0.02,
        vel_x := g_sim_trans[2].XVelocity, z_stage := g_sim_trans[2].ZStage,
        lift_stn := g_transporter[2].LiftStationTarget,
        sink_stn := g_transporter[2].SinkStationTarget,
        from_stn := g_transporter[2].CurrentStation);
  ELSIF i = 3 THEN
    tm3(t_id := 3, phase := g_transporter[3].Phase, delta_t := 0.02,
        vel_x := g_sim_trans[3].XVelocity, z_stage := g_sim_trans[3].ZStage,
        lift_stn := g_transporter[3].LiftStationTarget,
        sink_stn := g_transporter[3].SinkStationTarget,
        from_stn := g_transporter[3].CurrentStation);
  END_IF;

  END_IF;  (* active *)
END_FOR;

(* Convert DINT/INT inputs to REAL for physics *)
r_target := DINT_TO_REAL(x_target);
r_min    := DINT_TO_REAL(x_min);
r_max    := DINT_TO_REAL(x_max);
r_vmax   := DINT_TO_REAL(v_max);
r_tacc   := DINT_TO_REAL(t_acc) / 10.0;
r_tdec   := DINT_TO_REAL(t_dec) / 10.0;
r_pos    := DINT_TO_REAL(x_pos);
r_vel    := DINT_TO_REAL(v_x);

IF (r_max > r_min) THEN
  IF r_pos < r_min THEN
    drive_target := r_min;
  ELSIF r_pos > r_max THEN
    drive_target := r_max;
  ELSE
    IF r_target < r_min THEN
      drive_target := r_min;
    ELSIF r_target > r_max THEN
      drive_target := r_max;
    ELSE
      drive_target := r_target;
    END_IF;
  END_IF;
ELSE
  drive_target := r_target;
END_IF;

arrived := ABS(r_pos - drive_target) <= 3.0;
IF arrived THEN
  x_pos := REAL_TO_DINT(drive_target);
  v_x := 0;
  RETURN;
END_IF;

IF r_tacc <= 0.0 THEN r_tacc := 0.001; END_IF;
IF r_tdec <= 0.0 THEN r_tdec := 0.001; END_IF;
IF r_vmax < 0.0 THEN r_vmax := 0.0; END_IF;

a_acc := r_vmax / r_tacc;
a_dec := r_vmax / r_tdec;

dir := 1.0;
IF drive_target < r_pos THEN
  dir := -1.0;
END_IF;

distance := ABS(drive_target - r_pos);

IF a_dec > 0.0 THEN
  brake_dist := (r_vel * r_vel) / (2.0 * a_dec);
ELSE
  brake_dist := 0.0;
END_IF;

IF brake_dist >= distance THEN
  new_vel := r_vel - a_dec * delta_t;
  IF new_vel < 0.0 THEN new_vel := 0.0; END_IF;
ELSE
  new_vel := r_vel + a_acc * delta_t;
  IF new_vel > r_vmax THEN new_vel := r_vmax; END_IF;
END_IF;

travel := new_vel * delta_t;
IF travel >= distance THEN
  x_pos := REAL_TO_DINT(drive_target);
  v_x := 0;
  arrived := TRUE;
ELSE
  x_pos := REAL_TO_DINT(r_pos + dir * travel);
  v_x := REAL_TO_DINT(new_vel);
  arrived := FALSE;
END_IF;

done := FALSE;
z_total_mm := ZPosDown - ZPosUp;

(* Convert DINT/INT inputs to REAL for physics *)
r_z         := DINT_TO_REAL(z_mm);
r_total     := DINT_TO_REAL(z_total_mm);
r_slow_end  := DINT_TO_REAL(ZPosSlowEnd);
r_slow_spd  := DINT_TO_REAL(SpeedLiftSlow_Z);
r_fast_spd  := DINT_TO_REAL(SpeedLiftFast_Z);
r_drip      := INT_TO_REAL(DripTrayDelay) / 10.0;

(* Select slow zone based on station kind *)
IF station_kind = KIND_WET THEN
  r_slow_zone := DINT_TO_REAL(ZPosSlowDown);
ELSE
  r_slow_zone := DINT_TO_REAL(ZPosSlowUp);
END_IF;

CASE z_stage OF

  (* === LIFT: stages 1-5 — nosto altaasta ylös (z kasvaa: 0 → z_total) === *)

  1: (* Init delay: device_delay + dropping_time *)
    z_timer_s := z_timer_s - delta_t;
    IF z_timer_s <= 0.0 THEN
      z_stage := 2;
      z_mm := 0;
    END_IF;

  2: (* Slow lift start — hidas nosto nesteestä *)
    r_z := r_z + r_slow_spd * delta_t;
    z_mm := REAL_TO_DINT(r_z);
    IF r_z >= r_slow_zone THEN
      z_stage := 3;
    END_IF;

  3: (* Fast lift — nopea nosto *)
    r_z := r_z + r_fast_spd * delta_t;
    z_mm := REAL_TO_DINT(r_z);
    IF r_z >= (r_total - r_slow_end) THEN
      z_stage := 4;
    END_IF;

  4: (* Slow lift end — hidas loppunosto *)
    r_z := r_z + r_slow_spd * delta_t;
    IF r_z >= r_total THEN
      z_mm := z_total_mm;
      z_timer_s := r_drip;
      z_stage := 5;
    ELSE
      z_mm := REAL_TO_DINT(r_z);
    END_IF;

  5: (* Drip delay — tippumisviive yläasemassa *)
    z_timer_s := z_timer_s - delta_t;
    IF z_timer_s <= 0.0 THEN
      z_stage := 0;
      done := TRUE;
    END_IF;

  (* === SINK: stages 6-8 — lasku altaaseen (z pienenee: z_total → 0) === *)

  6: (* Init delay: device_delay + drip_delay *)
    z_timer_s := z_timer_s - delta_t;
    IF z_timer_s <= 0.0 THEN
      z_stage := 7;
    END_IF;

  7: (* Fast sink — nopea lasku *)
    r_z := r_z - r_fast_spd * delta_t;
    z_mm := REAL_TO_DINT(r_z);
    IF r_z <= r_slow_zone THEN
      z_stage := 8;
    END_IF;

  8: (* Slow sink — hidas lasku nesteeseen *)
    r_z := r_z - r_slow_spd * delta_t;
    IF r_z <= 0.0 THEN
      z_mm := 0;
      z_stage := 0;
      done := TRUE;
    ELSE
      z_mm := REAL_TO_DINT(r_z);
    END_IF;

END_CASE;

(* Rising edge detection *)
IF i_run AND NOT prev_run THEN

  (* Determine last active station *)
  last_stn := MIN_StationIndex + g_station_count - 1;
  IF last_stn > MAX_StationIndex THEN
    last_stn := MAX_StationIndex;
  END_IF;

  FOR tid := 1 TO MAX_Transporters DO
    (* Skip transporters without valid calibration data *)
    IF g_cal[tid].XMaxSpeed >= 1 THEN

      vm := DINT_TO_REAL(g_cal[tid].XMaxSpeed);
      ta := INT_TO_REAL(g_cal[tid].XAccelTime) / 10.0;
      td := INT_TO_REAL(g_cal[tid].XDecelTime) / 10.0;
      d_acc := 0.5 * vm * ta;
      d_dec := 0.5 * vm * td;

      (* --- Lift and sink times per station --- *)
      FOR si := MIN_StationIndex TO last_stn DO
        idx_i := si - MIN_StationIndex + 1;
        IF idx_i >= 1 AND idx_i <= 30 THEN
          IF g_station[si].DryWet = 1 THEN
            (* Wet station *)
            g_move[tid].LiftTime[idx_i] := g_cal[tid].LiftWetTime;
            g_move[tid].SinkTime[idx_i] := g_cal[tid].SinkWetTime;
          ELSE
            (* Dry station *)
            g_move[tid].LiftTime[idx_i] := g_cal[tid].LiftDryTime;
            g_move[tid].SinkTime[idx_i] := g_cal[tid].SinkDryTime;
          END_IF;
        END_IF;
      END_FOR;

      (* --- Travel times between stations --- *)
      FOR si := MIN_StationIndex TO last_stn DO
        idx_i := si - MIN_StationIndex + 1;
        IF idx_i >= 1 AND idx_i <= 30 THEN
          FOR sj := MIN_StationIndex TO last_stn DO
            idx_j := sj - MIN_StationIndex + 1;
            IF idx_j >= 1 AND idx_j <= 30 THEN
              IF si = sj THEN
                g_move[tid].Travel[idx_i].ToTime[idx_j] := 0;
              ELSE
                dist := ABS(DINT_TO_REAL(g_station[si].XPosition - g_station[sj].XPosition));
                IF dist < 1.0 THEN
                  t_time := 0.0;
                ELSIF dist >= d_acc + d_dec THEN
                  (* Trapezoidal profile: full accel + cruise + full decel *)
                  t_time := ta + (dist - d_acc - d_dec) / vm + td;
                ELSE
                  (* Triangle profile: cannot reach full speed *)
                  IF ta + td > 0.0 THEN
                    v_peak := SQRT(2.0 * dist * vm / (ta + td));
                    t_time := v_peak * (ta + td) / vm;
                  ELSE
                    t_time := 0.0;
                  END_IF;
                END_IF;
                g_move[tid].Travel[idx_i].ToTime[idx_j] := REAL_TO_INT(t_time * 10.0);
              END_IF;
            END_IF;
          END_FOR;
        END_IF;
      END_FOR;

    END_IF;  (* valid calibration check *)
  END_FOR;

END_IF;

prev_run := i_run;

IF NOT i_run THEN
  RETURN;
END_IF;

(* ── Command handling ── *)
IF i_cmd = 1 AND cal_step = 0 THEN
  (* Start calibration — find first active transporter with plan *)
  tid := 0;
  FOR ci := 1 TO MAX_Transporters DO
    IF g_transporter[ci].IsActive AND tid = 0 THEN
      IF g_cal[ci].WetStation > 0 AND g_cal[ci].DryStation > 0 THEN
        tid := ci;
      END_IF;
    END_IF;
  END_FOR;
  IF tid > 0 THEN
    cal_step := 10;
    o_active := TRUE;
  END_IF;
END_IF;

IF i_cmd = 2 AND cal_step = 100 THEN
  (* Calculate g_move from measured parameters *)
  cal_step := 200;
END_IF;

IF i_cmd = 3 THEN
  (* Abort — reset to idle *)
  cal_step := 0;
  tid := 0;
  o_active := FALSE;
END_IF;

(* ================================================================
   STEP 10-12: TASK 1 — lift=dry_station, sink=wet_station
   MeasureMoveTimes records lift_s[dry], sink_s[wet], travel[dry→wet].
   X velocity profile measured during phase 3 (travel dry→wet).
   ================================================================ *)
IF cal_step = 10 THEN
  (* Issue task 1: lift from dry, sink to wet *)
  task_key := g_time_s;
  g_transporter[tid].TaskId := task_key;
  g_transporter[tid].LiftStationTarget := g_cal[tid].DryStation;
  g_transporter[tid].SinkStationTarget := g_cal[tid].WetStation;
  (* Reset X velocity measurement *)
  x_meas_ph := 0;
  x_timer   := 0.0;
  x_prev_v  := 0.0;
  x_max_v   := 0.0;
  x_acc_t   := 0.0;
  x_dec_t   := 0.0;
  cal_step := 11;
END_IF;

IF cal_step = 11 THEN
  (* Wait for task acceptance *)
  IF g_sim_trans[tid].RunningTaskId = task_key THEN
    cal_step := 12;
  END_IF;
END_IF;

IF cal_step = 12 THEN
  cur_v := ABS(DINT_TO_REAL(g_sim_trans[tid].XVelocity));

  (* ── Track X velocity during phase 3 (travel dry→wet) ── *)
  IF g_transporter[tid].Phase = 3 THEN
    IF x_meas_ph = 0 AND cur_v > 0.5 THEN
      (* Acceleration started *)
      x_meas_ph := 1;
      x_timer := 0.02;
      x_prev_v := cur_v;
      x_max_v := cur_v;

    ELSIF x_meas_ph = 1 THEN
      x_timer := x_timer + 0.02;
      IF cur_v > x_max_v THEN
        x_max_v := cur_v;
      END_IF;
      IF cur_v <= x_prev_v THEN
        (* Velocity stopped increasing → reached v_max *)
        x_acc_t := x_timer - 0.02;
        x_meas_ph := 2;
        x_timer := 0.0;
      END_IF;
      x_prev_v := cur_v;

    ELSIF x_meas_ph = 2 THEN
      (* Cruising — wait for deceleration *)
      IF cur_v < x_max_v - 1.0 THEN
        x_meas_ph := 3;
        x_timer := 0.02;
      END_IF;

    ELSIF x_meas_ph = 3 THEN
      x_timer := x_timer + 0.02;
    END_IF;
  END_IF;

  (* ── Phase 3 ended or phase 4 reached: store X results ── *)
  IF g_transporter[tid].Phase >= 4 AND x_meas_ph >= 1 THEN
    IF x_meas_ph = 3 THEN
      x_dec_t := x_timer;
    END_IF;
    g_cal[tid].XAccelTime  := REAL_TO_INT(x_acc_t * 10.0);
    g_cal[tid].XDecelTime  := REAL_TO_INT(x_dec_t * 10.0);
    g_cal[tid].XMaxSpeed := REAL_TO_DINT(x_max_v);
    (* Don't re-enter — set meas_ph to done *)
    x_meas_ph := 99;
  END_IF;

  (* ── Wait for full task completion (phase returns to 0) ── *)
  IF g_transporter[tid].Phase = 0 AND x_meas_ph >= 99 THEN
    cal_step := 20;
  END_IF;
END_IF;

(* ================================================================
   STEP 20-22: TASK 2 — lift=wet_station, sink=dry_station
   MeasureMoveTimes records lift_s[wet], sink_s[dry], travel[wet→dry].
   ================================================================ *)
IF cal_step = 20 THEN
  (* Issue task 2: lift from wet, sink to dry *)
  task_key := g_time_s + LINT#1;
  g_transporter[tid].TaskId := task_key;
  g_transporter[tid].LiftStationTarget := g_cal[tid].WetStation;
  g_transporter[tid].SinkStationTarget := g_cal[tid].DryStation;
  cal_step := 21;
END_IF;

IF cal_step = 21 THEN
  IF g_sim_trans[tid].RunningTaskId = task_key THEN
    cal_step := 22;
  END_IF;
END_IF;

IF cal_step = 22 THEN
  (* Wait for task completion *)
  IF g_transporter[tid].Phase = 0 THEN
    cal_step := 30;
  END_IF;
END_IF;

(* ================================================================
   STEP 30: READ RESULTS FROM g_move → g_cal
   MeasureMoveTimes has recorded all 4 lift/sink times into g_move.
   ================================================================ *)
IF cal_step = 30 THEN
  wet_idx := g_cal[tid].WetStation - 100;
  dry_idx := g_cal[tid].DryStation - 100;

  IF wet_idx >= 1 AND wet_idx <= 25 THEN
    g_cal[tid].LiftWetTime := g_move[tid].LiftTime[wet_idx];
    g_cal[tid].SinkWetTime := g_move[tid].SinkTime[wet_idx];
  END_IF;

  IF dry_idx >= 1 AND dry_idx <= 25 THEN
    g_cal[tid].LiftDryTime := g_move[tid].LiftTime[dry_idx];
    g_cal[tid].SinkDryTime := g_move[tid].SinkTime[dry_idx];
  END_IF;

  cal_step := 40;
END_IF;

(* ================================================================
   STEP 40: TRANSPORTER DONE — advance to next or finish
   ================================================================ *)
IF cal_step = 40 THEN
  (* Find next active transporter after current tid with plan *)
  next_tid := 0;
  FOR ci := tid + 1 TO MAX_Transporters DO
    IF g_transporter[ci].IsActive AND next_tid = 0 THEN
      IF g_cal[ci].WetStation > 0 AND g_cal[ci].DryStation > 0 THEN
        next_tid := ci;
      END_IF;
    END_IF;
  END_FOR;

  IF next_tid > 0 THEN
    (* Calibrate next transporter *)
    tid := next_tid;
    cal_step := 10;
  ELSE
    (* All transporters done — measurement complete *)
    cal_step := 100;
  END_IF;
END_IF;

(* ================================================================
   STEP 200: CALCULATE g_move FROM MEASURED PARAMETERS
   For each active transporter with calibration data:
     - Copy lift/sink wet times to all wet stations
     - Copy lift/sink dry times to all dry stations
     - Calculate all station-to-station travel times using
       measured v_max, t_acc, t_dec and station distances
   ================================================================ *)
IF cal_step = 200 THEN
  FOR ci := 1 TO MAX_Transporters DO
    IF g_transporter[ci].IsActive AND g_cal[ci].XMaxSpeed > 0 THEN

      vm := DINT_TO_REAL(g_cal[ci].XMaxSpeed);
      ta := INT_TO_REAL(g_cal[ci].XAccelTime) / 10.0;
      td := INT_TO_REAL(g_cal[ci].XDecelTime) / 10.0;

      (* --- Fill lift_s and sink_s per station type --- *)
      FOR cj := 1 TO 25 DO
        IF g_station[100 + cj].TankId <> 0 THEN
          IF g_station[100 + cj].DryWet = 1 THEN
            (* Wet station *)
            g_move[ci].LiftTime[cj] := g_cal[ci].LiftWetTime;
            g_move[ci].SinkTime[cj] := g_cal[ci].SinkWetTime;
          ELSE
            (* Dry station *)
            g_move[ci].LiftTime[cj] := g_cal[ci].LiftDryTime;
            g_move[ci].SinkTime[cj] := g_cal[ci].SinkDryTime;
          END_IF;
        END_IF;
      END_FOR;

      (* --- Calculate all travel times from kinematics --- *)
      (* d_acc = 0.5 * v_max * t_acc (distance during acceleration)
         d_dec = 0.5 * v_max * t_dec (distance during deceleration)
         If dist >= d_acc + d_dec:
           travel = t_acc + (dist - d_acc - d_dec) / v_max + t_dec
         Else (triangle profile):
           v_peak = SQRT(2 * dist * v_max / (t_acc + t_dec))
           travel = v_peak * (t_acc + t_dec) / v_max *)
      d_acc := 0.5 * vm * ta;
      d_dec := 0.5 * vm * td;

      FOR cj := 1 TO 25 DO
        IF g_station[100 + cj].TankId <> 0 THEN
          FOR wet_idx := 1 TO 25 DO
            IF g_station[100 + wet_idx].TankId <> 0 THEN
              IF cj = wet_idx THEN
                g_move[ci].Travel[cj].ToTime[wet_idx] := 0;
              ELSE
                dist := ABS(DINT_TO_REAL(g_station[100 + cj].XPosition - g_station[100 + wet_idx].XPosition));
                IF dist < 1.0 THEN
                  g_move[ci].Travel[cj].ToTime[wet_idx] := 0;
                ELSIF dist >= (d_acc + d_dec) THEN
                  (* Full trapezoidal profile *)
                  travel_t := ta + (dist - d_acc - d_dec) / vm + td;
                  g_move[ci].Travel[cj].ToTime[wet_idx] := REAL_TO_INT(travel_t * 10.0);
                ELSE
                  (* Triangle profile — cannot reach full speed *)
                  IF (ta + td) > 0.0 THEN
                    v_peak := SQRT(2.0 * dist * vm / (ta + td));
                    travel_t := v_peak * (ta + td) / vm;
                    g_move[ci].Travel[cj].ToTime[wet_idx] := REAL_TO_INT(travel_t * 10.0);
                  ELSE
                    g_move[ci].Travel[cj].ToTime[wet_idx] := 0;
                  END_IF;
                END_IF;
              END_IF;
            END_IF;
          END_FOR;
        END_IF;
      END_FOR;

    END_IF;
  END_FOR;

  cal_step := 999;
END_IF;

(* ── Update outputs ── *)
o_step := cal_step;
o_tid  := tid;
IF cal_step > 0 AND cal_step < 999 THEN
  o_active := TRUE;
ELSIF cal_step = 999 THEN
  o_active := FALSE;
ELSE
  o_active := FALSE;
END_IF;

FOR ti := 1 TO MAX_Transporters DO
  g_task[ti].Count := 0;
  FOR qi := 1 TO MAX_TASK_QUEUE DO
    g_task[ti].Queue[qi].Unit         := 0;
    g_task[ti].Queue[qi].Stage        := 0;
    g_task[ti].Queue[qi].LiftStationTarget := 0;
    g_task[ti].Queue[qi].SinkStationTarget := 0;
    g_task[ti].Queue[qi].StartTime   := 0;
    g_task[ti].Queue[qi].FinishTime  := 0;
    g_task[ti].Queue[qi].CalcTime    := 0;
    g_task[ti].Queue[qi].MinTime     := 0;
    g_task[ti].Queue[qi].MaxTime     := 0;
  END_FOR;
END_FOR;

o_count := 0;
FOR ui := 1 TO MAX_Units DO
  o_list[ui] := 0;
END_FOR;

FOR ui := 1 TO MAX_Units DO
  (* Common conditions: unit USED, target TO_NONE, valid program *)
  IF g_unit[ui].Status = 1
     AND g_unit[ui].Target = 0
     AND g_batch[ui].ProgId = g_program[ui].ProgramId
     AND g_program[ui].ProgramId > 0 THEN

    IF i_mode = 0 THEN
      (* Active batches: IN_PROCESS, stage 0..99 *)
      IF g_batch[ui].State = 1
         AND g_batch[ui].CurStage >= 0
         AND g_batch[ui].CurStage <= 99 THEN
        o_count := o_count + 1;
        o_list[o_count] := ui;
      END_IF;
    ELSIF i_mode = 1 THEN
      (* Waiting batches: NOT_PROCESSED *)
      IF g_batch[ui].State = 0 THEN
        o_count := o_count + 1;
        o_list[o_count] := ui;
      END_IF;
    END_IF;
  END_IF;
END_FOR;

FOR ti := 1 TO MAX_Transporters DO

  (* ── 1. Skip if not idle or queue empty ── *)
  IF g_transporter[ti].Phase = 0 AND g_task[ti].Count >= 1 THEN

    (* Read task fields from queue position 1 *)
    t_unit      := g_task[ti].Queue[1].Unit;
    t_stage     := g_task[ti].Queue[1].Stage;
    t_lift      := g_task[ti].Queue[1].LiftStationTarget;
    t_sink      := g_task[ti].Queue[1].SinkStationTarget;
    t_start     := g_task[ti].Queue[1].StartTime;
    t_finish    := g_task[ti].Queue[1].FinishTime;
    t_calc_time := g_task[ti].Queue[1].CalcTime;

    (* ── 2. Time check ── *)
    travel_s := 0.0;
    IF g_transporter[ti].CurrentStation > 0 AND t_lift > 0
       AND g_transporter[ti].CurrentStation <> t_lift THEN
      from_idx := g_transporter[ti].CurrentStation - 100;
      to_idx   := t_lift - 100;
      IF from_idx >= 1 AND from_idx <= 30 AND to_idx >= 1 AND to_idx <= 30 THEN
        travel_s := INT_TO_REAL(g_move[ti].Travel[from_idx].ToTime[to_idx]) / 10.0;
      END_IF;
    END_IF;

    margin_s := t_start - g_time_s;

    IF margin_s <= REAL_TO_LINT(travel_s) + 3 THEN

      (* ── 3. Sink station free check ── *)
      sink_stn := t_sink;
      sink_free := FALSE;

      IF sink_stn >= MIN_StationIndex AND sink_stn <= MAX_StationIndex THEN
        sink_free := TRUE;
        FOR uj := 1 TO MAX_Units DO
          IF g_unit[uj].location = sink_stn AND g_unit[uj].Status = 1 THEN
            sink_free := FALSE;
          END_IF;
        END_FOR;
      END_IF;

      IF NOT sink_free THEN
        (* Search alternative parallel stations *)
        best_stn := 0;
        best_change := LINT#2000000000;

        IF t_stage >= 1 AND t_stage <= MAX_STEPS_PER_PROGRAM
           AND t_unit >= 1 AND t_unit <= MAX_Units THEN
          (* Treatment task — look in g_program for parallel stations *)
          FOR si := 0 TO MAX_STATIONS_PER_STEP - 1 DO
            cand_stn := g_program[t_unit].Steps[t_stage - 1].Stations[si];
            IF cand_stn > 0 AND cand_stn <> t_sink THEN
              IF cand_stn >= MIN_StationIndex AND cand_stn <= MAX_StationIndex THEN
                cand_free := TRUE;
                FOR uj := 1 TO MAX_Units DO
                  IF g_unit[uj].location = cand_stn AND g_unit[uj].Status = 1 THEN
                    cand_free := FALSE;
                  END_IF;
                END_FOR;
                IF cand_free THEN
                  IF g_station_loc[cand_stn].ChangeTime < best_change THEN
                    best_change := g_station_loc[cand_stn].ChangeTime;
                    best_stn := cand_stn;
                  END_IF;
                END_IF;
              END_IF;
            END_IF;
          END_FOR;

        ELSIF t_stage = 0 AND t_unit >= 1 AND t_unit <= MAX_Units THEN
          (* No-treatment task — look in g_ntt for alternatives *)
          tgt := g_unit[t_unit].Target;
          IF tgt >= 1 AND tgt <= 5 THEN
            (* Resolve buffer NTT index like NoTreatment does *)
            IF tgt = 2 THEN
              IF g_batch[t_unit].BatchCode = 0 THEN
                ntt_idx := 6;
              ELSIF g_batch[t_unit].State = 2 THEN
                ntt_idx := 8;
              ELSE
                ntt_idx := 7;
              END_IF;
            ELSE
              ntt_idx := tgt;
            END_IF;
            (* Check primary stations *)
            ntt_cnt := g_ntt[ti].Target[ntt_idx].StationCount;
            FOR si := 1 TO ntt_cnt DO
              IF si <= MAX_STATIONS_PER_STEP THEN
                cand_stn := g_ntt[ti].Target[ntt_idx].Stations[si];
                IF cand_stn > 0 AND cand_stn <> t_sink THEN
                  IF cand_stn >= MIN_StationIndex AND cand_stn <= MAX_StationIndex THEN
                    cand_free := TRUE;
                    FOR uj := 1 TO MAX_Units DO
                      IF g_unit[uj].location = cand_stn AND g_unit[uj].Status = 1 THEN
                        cand_free := FALSE;
                      END_IF;
                    END_FOR;
                    IF cand_free THEN
                      IF g_station_loc[cand_stn].ChangeTime < best_change THEN
                        best_change := g_station_loc[cand_stn].ChangeTime;
                        best_stn := cand_stn;
                      END_IF;
                    END_IF;
                  END_IF;
                END_IF;
              END_IF;
            END_FOR;
            (* Check fallback stations *)
            ntt_fb_cnt := g_ntt[ti].Target[ntt_idx].FallbackCount;
            FOR si := 1 TO ntt_fb_cnt DO
              IF si <= MAX_STATIONS_PER_STEP THEN
                cand_stn := g_ntt[ti].Target[ntt_idx].FallbackStations[si];
                IF cand_stn > 0 AND cand_stn <> t_sink THEN
                  IF cand_stn >= MIN_StationIndex AND cand_stn <= MAX_StationIndex THEN
                    cand_free := TRUE;
                    FOR uj := 1 TO MAX_Units DO
                      IF g_unit[uj].location = cand_stn AND g_unit[uj].Status = 1 THEN
                        cand_free := FALSE;
                      END_IF;
                    END_FOR;
                    IF cand_free THEN
                      IF g_station_loc[cand_stn].ChangeTime < best_change THEN
                        best_change := g_station_loc[cand_stn].ChangeTime;
                        best_stn := cand_stn;
                      END_IF;
                    END_IF;
                  END_IF;
                END_IF;
              END_IF;
            END_FOR;
          END_IF;
        END_IF;

        IF best_stn > 0 THEN
          sink_stn := best_stn;
          sink_free := TRUE;
        END_IF;
      END_IF;  (* NOT sink_free *)

      IF sink_free THEN

        (* ── 4. Conflict check ── *)
        (* Check against other transporters' ACTIVE tasks (phase>0).
           Two rules:
           a) T2's entire task (lift AND sink) is inside our task
              range [task_min..task_max] → conflict.
              Example: our 114→101 range [101,114]
                T2 114→113: both in [101,114] → conflict
                T2 114→117: 117 outside     → no conflict (going away)
           b) T2 delivers (sink) to one of our exact stations
              from outside our range → conflict.
              Example: T2 120→114, 114 is our lift → conflict *)
        conflict := FALSE;

        IF t_lift <= sink_stn THEN
          task_min := t_lift;
          task_max := sink_stn;
        ELSE
          task_min := sink_stn;
          task_max := t_lift;
        END_IF;

        FOR cj := 1 TO MAX_Transporters DO
          IF cj <> ti AND g_transporter[cj].Phase > 0 THEN

            (* a) T2's entire active task inside our range → conflict *)
            IF g_transporter[cj].LiftStationTarget >= task_min
               AND g_transporter[cj].LiftStationTarget <= task_max
               AND g_transporter[cj].SinkStationTarget >= task_min
               AND g_transporter[cj].SinkStationTarget <= task_max THEN
              conflict := TRUE;
            END_IF;

            (* b) T2 delivers to one of our exact stations → conflict *)
            IF g_transporter[cj].SinkStationTarget = t_lift
               OR g_transporter[cj].SinkStationTarget = sink_stn THEN
              conflict := TRUE;
            END_IF;

          END_IF;
        END_FOR;

        IF NOT conflict THEN
          (* ── 5. Dispatch: assign task to transporter ── *)
          g_transporter[ti].TaskId      := t_start;
          g_transporter[ti].LiftStationTarget := t_lift;
          g_transporter[ti].SinkStationTarget := sink_stn;
          g_station_loc[ti].UnitId      := t_unit;
          g_sim_trans[ti].TreatmentTime := t_calc_time;
          g_sim_trans[ti].MinTime := g_task[ti].Queue[1].MinTime;
          g_sim_trans[ti].MaxTime := g_task[ti].Queue[1].MaxTime;
          g_transporter[ti].TaskRemainingTime := t_calc_time;

          (* ── Update batch times: transfer duration as time bar ── *)
          IF t_unit >= 1 AND t_unit <= MAX_Units THEN
            g_batch[t_unit].StartTime := g_time_s;
            g_batch[t_unit].CalTime   := LINT_TO_DINT(t_finish - t_start);
            g_batch[t_unit].MinTime   := g_batch[t_unit].CalTime;
            g_batch[t_unit].MaxTime   := LINT_TO_DINT((t_finish - t_start) * LINT#2);
          END_IF;

          (* ── Emit TASK_DISPATCHED event (msg_type=1) ── *)
          IF NOT g_event_pending_valid THEN
            g_event_pending.MsgType := 1;
            g_event_pending.TsHi := LINT_TO_INT(g_time_s / LINT#65536);
            g_event_pending.TsLo := LINT_TO_INT(g_time_s MOD LINT#65536);
            g_event_pending.Payload[1]  := ti;
            g_event_pending.Payload[2]  := t_unit;
            g_event_pending.Payload[3]  := t_lift;
            g_event_pending.Payload[4]  := sink_stn;
            g_event_pending.Payload[5]  := t_stage;
            g_event_pending.Payload[6]  := g_batch[t_unit].BatchCode;
            g_event_pending.Payload[7]  := g_batch[t_unit].State;
            g_event_pending.Payload[8]  := g_batch[t_unit].ProgId;
            g_event_pending.Payload[9]  := g_unit[t_unit].Target;
            g_event_pending.Payload[10] := DINT_TO_INT(t_calc_time);
            g_event_pending.Payload[11] := DINT_TO_INT(g_task[ti].Queue[1].MinTime);
            g_event_pending.Payload[12] := DINT_TO_INT(g_task[ti].Queue[1].MaxTime);
            g_event_pending_valid := TRUE;
          END_IF;

          (* Copy station-specific timing from config *)
          IF t_lift >= MIN_StationIndex AND t_lift <= MAX_StationIndex THEN
            g_transporter[ti].DrippingTime := g_station[t_lift].DrippingTime;
            g_sim_trans[ti].LiftDeviceDelay := g_station[t_lift].DeviceDelay;
          END_IF;
          IF sink_stn >= MIN_StationIndex AND sink_stn <= MAX_StationIndex THEN
            g_sim_trans[ti].SinkDeviceDelay := g_station[sink_stn].DeviceDelay;
          END_IF;

          (* Shift queue: remove position 1, move rest up *)
          FOR sh := 2 TO g_task[ti].Count DO
            g_task[ti].Queue[sh - 1] := g_task[ti].Queue[sh];
          END_FOR;
          (* Clear last slot *)
          g_task[ti].Queue[g_task[ti].Count].Unit := 0;
          g_task[ti].Queue[g_task[ti].Count].Stage := 0;
          g_task[ti].Queue[g_task[ti].Count].LiftStationTarget := 0;
          g_task[ti].Queue[g_task[ti].Count].SinkStationTarget := 0;
          g_task[ti].Queue[g_task[ti].Count].StartTime := 0;
          g_task[ti].Queue[g_task[ti].Count].FinishTime := 0;
          g_task[ti].Queue[g_task[ti].Count].CalcTime := 0;
          g_task[ti].Queue[g_task[ti].Count].MinTime := 0;
          g_task[ti].Queue[g_task[ti].Count].MaxTime := 0;
          g_task[ti].Count := g_task[ti].Count - 1;

        END_IF;  (* NOT conflict *)

      END_IF;  (* sink_free *)

    END_IF;  (* time check *)

  END_IF;  (* idle + queue *)

END_FOR;

(* ── 1. Enqueue: pick up pending message if queue not full ── *)
IF g_event_pending_valid AND g_event.Count < 10 THEN
  (* Calculate tail position in circular buffer *)
  tail := ((g_event.Head - 1 + g_event.Count) MOD 10) + 1;

  (* Assign sequence number *)
  g_event_pending.Seq := g_event.NextSeq;
  g_event.NextSeq := g_event.NextSeq + 1;
  IF g_event.NextSeq > 32000 THEN
    g_event.NextSeq := 1;  (* wrap to avoid INT overflow *)
  END_IF;

  (* Store in buffer *)
  g_event.Buffer[tail] := g_event_pending;
  g_event.Count := g_event.Count + 1;

  (* Clear pending flag *)
  g_event_pending_valid := FALSE;
END_IF;

(* ── 2. Dequeue: check gateway ack for head message ── *)
IF g_event.Count > 0 THEN
  IF iw_event_ack_seq = g_event.Buffer[g_event.Head].Seq THEN
    (* Gateway consumed this message — advance head *)
    g_event.Head := (g_event.Head MOD 10) + 1;
    g_event.Count := g_event.Count - 1;
  END_IF;
END_IF;

(* ── 3. Publish: copy head message to Modbus QW registers ── *)
qw_event_out_count := g_event.Count;

IF g_event.Count > 0 THEN
  qw_event_out_seq    := g_event.Buffer[g_event.Head].Seq;
  qw_event_out_type   := g_event.Buffer[g_event.Head].MsgType;
  qw_event_out_ts_hi  := g_event.Buffer[g_event.Head].TsHi;
  qw_event_out_ts_lo  := g_event.Buffer[g_event.Head].TsLo;
  qw_event_out_f1     := g_event.Buffer[g_event.Head].Payload[1];
  qw_event_out_f2     := g_event.Buffer[g_event.Head].Payload[2];
  qw_event_out_f3     := g_event.Buffer[g_event.Head].Payload[3];
  qw_event_out_f4     := g_event.Buffer[g_event.Head].Payload[4];
  qw_event_out_f5     := g_event.Buffer[g_event.Head].Payload[5];
  qw_event_out_f6     := g_event.Buffer[g_event.Head].Payload[6];
  qw_event_out_f7     := g_event.Buffer[g_event.Head].Payload[7];
  qw_event_out_f8     := g_event.Buffer[g_event.Head].Payload[8];
  qw_event_out_f9     := g_event.Buffer[g_event.Head].Payload[9];
  qw_event_out_f10    := g_event.Buffer[g_event.Head].Payload[10];
  qw_event_out_f11    := g_event.Buffer[g_event.Head].Payload[11];
  qw_event_out_f12    := g_event.Buffer[g_event.Head].Payload[12];
ELSE
  (* Queue empty — clear output *)
  qw_event_out_seq    := 0;
  qw_event_out_type   := 0;
  qw_event_out_ts_hi  := 0;
  qw_event_out_ts_lo  := 0;
  qw_event_out_f1     := 0;
  qw_event_out_f2     := 0;
  qw_event_out_f3     := 0;
  qw_event_out_f4     := 0;
  qw_event_out_f5     := 0;
  qw_event_out_f6     := 0;
  qw_event_out_f7     := 0;
  qw_event_out_f8     := 0;
  qw_event_out_f9     := 0;
  qw_event_out_f10    := 0;
  qw_event_out_f11    := 0;
  qw_event_out_f12    := 0;
END_IF;

(* Direct lookup by station number — no loop needed *)
IF (station_number >= MIN_StationIndex) AND (station_number <= MAX_StationIndex) THEN
  st := g_station[station_number];
  IF st.TankId <> 0 THEN
    found := TRUE;
    idx := station_number;
    x_mm := st.XPosition;
    skind := st.DryWet;
    device_delay_s := INT_TO_REAL(st.DeviceDelay) / 10.0;
    dropping_time_s := INT_TO_REAL(st.DrippingTime) / 10.0;
    RETURN;
  END_IF;
END_IF;

found := FALSE;
idx := 0;
x_mm := 0;
skind := 0;
device_delay_s := 0.0;
dropping_time_s := 0.0;

IF NOT i_run THEN
  (* Stop both schedulers *)
  tsk_sched(i_run := FALSE, i_time_s := 0);
  dep_sched(i_run := FALSE, i_time_s := 0, i_tsk_phase := 0);
  turn := 0;
  tsk_phase := 0;
  o_tsk_phase := 0;
  o_dep_phase := 0;
  o_turn := 0;
  RETURN;
END_IF;

(* ── Inhibit during calibration ── *)
IF g_cal_active THEN
  tsk_sched(i_run := FALSE, i_time_s := 0);
  dep_sched(i_run := FALSE, i_time_s := 0, i_tsk_phase := 0);
  turn := 0;
  RETURN;
END_IF;

(* ── Dispatch tasks to idle transporters (every scan) ── *)
dispatch();

(* ── Determine this cycle's turn ── *)
IF turn = 0 THEN
  (* First scan: always start with TSK *)
  turn := 1;

ELSIF turn = 1 THEN
  (* Last cycle was TSK → normally DEP's turn *)
  (* But skip DEP if: *)
  (*   a) TSK has not reached READY yet (phase < 10000) *)
  (*   b) pending data waiting for TSK to process *)
  IF tsk_phase < 10000 THEN
    (* TSK still computing — DEP would be blocked at WAIT_STABLE *)
    turn := 1;
    skip_cnt := skip_cnt + 1;
  ELSIF g_dep_pending.Valid THEN
    (* TSK must process pending before DEP continues *)
    turn := 1;
    skip_cnt := skip_cnt + 1;
  ELSE
    turn := 2;
  END_IF;

ELSIF turn = 2 THEN
  (* Last cycle was DEP → TSK's turn *)
  turn := 1;
END_IF;

(* ── Execute the selected scheduler ── *)
IF turn = 1 THEN
  (* TSK turn *)
  tsk_sched(i_run := TRUE, i_time_s := i_time_s);
  tsk_phase := tsk_sched.o_phase;

  (* Compute stability flag after TSK call *)
  g_dep_stable := (tsk_phase >= 10000);

ELSIF turn = 2 THEN
  (* DEP turn *)
  dep_sched(
    i_run       := TRUE,
    i_time_s    := i_time_s,
    i_tsk_phase := tsk_phase
  );
END_IF;

(* ── Update outputs ── *)
o_tsk_phase := tsk_sched.o_phase;
o_dep_phase := dep_sched.o_phase;
o_turn      := turn;
o_skip_cnt  := skip_cnt;

(* ---- Phase transition detection ---- *)
IF phase <> prev_phase THEN

  (* -- Save completed measurement and set up next -- *)

  IF prev_phase = 1 AND phase = 2 THEN
    (* Travel to lift complete → save travel time *)
    IF travel_from >= 1 AND travel_from <= 25
       AND travel_to >= 1 AND travel_to <= 25 THEN
      g_move[t_id].Travel[travel_from].ToTime[travel_to] := REAL_TO_INT(timer * 10.0);
    END_IF;
    (* Start timing lift — timer starts at 0, accumulates only in z_stage 2-4 *)
    lift_idx := lift_stn - 100;
    timer := 0.0;

  ELSIF prev_phase = 2 AND phase = 3 THEN
    (* Lift complete → save lift time (pure mechanical Z-motion only) *)
    IF lift_idx >= 1 AND lift_idx <= 25 THEN
      g_move[t_id].LiftTime[lift_idx] := REAL_TO_INT(timer * 10.0);
    END_IF;
    (* Start timing travel to sink *)
    travel_from := lift_stn - 100;
    travel_to := sink_stn - 100;
    timer := 0.0;

  ELSIF prev_phase = 3 AND phase = 4 THEN
    (* Travel to sink complete → save travel time *)
    IF travel_from >= 1 AND travel_from <= 25
       AND travel_to >= 1 AND travel_to <= 25 THEN
      g_move[t_id].Travel[travel_from].ToTime[travel_to] := REAL_TO_INT(timer * 10.0);
    END_IF;
    (* Start timing sink — timer starts at 0, accumulates only in z_stage 7-8 *)
    sink_idx := sink_stn - 100;
    timer := 0.0;

  ELSIF prev_phase = 4 AND phase = 0 THEN
    (* Sink complete → save sink time (pure mechanical Z-motion only) *)
    IF sink_idx >= 1 AND sink_idx <= 25 THEN
      g_move[t_id].SinkTime[sink_idx] := REAL_TO_INT(timer * 10.0);
    END_IF;
    timer := 0.0;

  ELSIF prev_phase = 0 AND phase = 1 THEN
    (* New cycle starting → set up travel-to-lift *)
    travel_from := from_stn - 100;
    travel_to := lift_stn - 100;
    timer := 0.0;

  ELSE
    (* Unexpected transition → just reset *)
    timer := 0.0;
  END_IF;

  prev_phase := phase;

ELSE
  (* ---- No transition: accumulate timer ---- *)

  IF phase = 1 OR phase = 3 THEN
    (* Travel: only count time when actually moving *)
    (* Filters out TWA collision avoidance stops    *)
    IF vel_x <> 0 THEN
      timer := timer + delta_t;
    END_IF;

  ELSIF phase = 2 THEN
    (* Lift: only mechanical Z-motion stages 2-4 *)
    (* Excludes: stage 1 (device_delay + dropping_time), stage 5 (drip_delay) *)
    IF z_stage >= 2 AND z_stage <= 4 THEN
      timer := timer + delta_t;
    END_IF;

  ELSIF phase = 4 THEN
    (* Sink: only mechanical Z-motion stages 7-8 *)
    (* Excludes: stage 6 (device_delay + drip_delay) *)
    IF z_stage >= 7 AND z_stage <= 8 THEN
      timer := timer + delta_t;
    END_IF;
  END_IF;

END_IF;

(* ════════════════════════════════════════════════════════════
   Pass 0 — SNAPSHOT: collect per-unit state in one pass
   ════════════════════════════════════════════════════════════ *)
has_loading := FALSE;

FOR u := 1 TO MAX_Units DO
  snap[u].IsActive := g_unit[u].Status <> NOT_USED;
  IF NOT snap[u].IsActive THEN
    CONTINUE;
  END_IF;

  snap[u].Location       := g_unit[u].location;
  snap[u].Target       := g_unit[u].Target;
  snap[u].HasBatch := g_batch[u].BatchCode <> 0;
  snap[u].BatchState    := g_batch[u].State;
  snap[u].CurStage := g_batch[u].CurStage;

  snap[u].OnStation := snap[u].Location >= MIN_StationIndex
                        AND snap[u].Location <= MAX_StationIndex;
  IF snap[u].OnStation THEN
    snap[u].LocationOp    := g_station[snap[u].Location].StationType;
    snap[u].InBuffer := snap[u].LocationOp >= 44 AND snap[u].LocationOp <= 47;
    IF g_station_loc[snap[u].Location].ChangeTime > 0 THEN
      snap[u].Elapsed := g_time_s - g_station_loc[snap[u].Location].ChangeTime;
    ELSE
      snap[u].Elapsed := 0;
    END_IF;
    snap[u].CalTime := g_program[u].Steps[snap[u].CurStage - 1].CalTime;
  ELSE
    snap[u].LocationOp    := 0;
    snap[u].InBuffer := FALSE;
    snap[u].Elapsed   := 0;
    snap[u].CalTime       := 0;
  END_IF;

  IF snap[u].Target = TO_LOADING THEN
    has_loading := TRUE;
  END_IF;
END_FOR;

(* ════════════════════════════════════════════════════════════
   Section 1 — PROCESSED: mark batch done at last treatment stage
   ════════════════════════════════════════════════════════════
   For each IN_PROCESS unit on a station:
     If next stage is empty (stations[1]=0) → last stage.
     If elapsed >= cal_time → set state := PROCESSED. *)
FOR u := 1 TO MAX_Units DO
  IF NOT snap[u].IsActive OR NOT snap[u].HasBatch THEN
    CONTINUE;
  END_IF;
  IF snap[u].BatchState <> IN_PROCESS OR NOT snap[u].OnStation THEN
    CONTINUE;
  END_IF;
  IF snap[u].CurStage >= 1 AND snap[u].CurStage < MAX_STEPS_PER_PROGRAM THEN
    IF snap[u].CurStage >= g_program[u].StepCount THEN
      IF snap[u].Elapsed > 0 AND snap[u].Elapsed >= DINT_TO_LINT(snap[u].CalTime) THEN
        g_batch[u].State := PROCESSED;
        snap[u].BatchState   := PROCESSED;  (* update snapshot *)
      END_IF;
    END_IF;
  END_IF;
END_FOR;

(* ════════════════════════════════════════════════════════════
   Section 2 — TO_AVOID: clear the way to next treatment station
   ════════════════════════════════════════════════════════════
   For each IN_PROCESS unit whose next stage exists:
     Pass 1: check if any next-stage station is free or already
             has a TO_AVOID unit (slot being cleared).
     Pass 2: if all occupied, mark ONE empty-batch TO_NONE unit
             at those stations as TO_AVOID. *)
FOR u := 1 TO MAX_Units DO
  IF NOT snap[u].IsActive OR NOT snap[u].HasBatch THEN
    CONTINUE;
  END_IF;
  IF snap[u].BatchState <> IN_PROCESS THEN
    CONTINUE;
  END_IF;
  IF snap[u].CurStage < 1 OR snap[u].CurStage >= MAX_STEPS_PER_PROGRAM THEN
    CONTINUE;
  END_IF;
  IF snap[u].CurStage >= g_program[u].StepCount THEN
    CONTINUE;  (* no next stage *)
  END_IF;

  (* — Pass 1: any next-stage station free or being cleared? — *)
  free_found := FALSE;
  avoid_uid  := 0;
  FOR p := 0 TO MAX_STATIONS_PER_STEP - 1 DO
    next_stn := g_program[u].Steps[snap[u].CurStage].Stations[p];
    IF next_stn = 0 THEN
      EXIT;
    END_IF;
    IF next_stn >= MIN_StationIndex AND next_stn <= MAX_StationIndex THEN
      IF g_station_loc[next_stn].UnitId = 0 THEN
        free_found := TRUE;
        EXIT;
      END_IF;
      occ_uid := g_station_loc[next_stn].UnitId;
      IF occ_uid >= 1 AND occ_uid <= MAX_Units THEN
        IF snap[occ_uid].Target = TO_AVOID THEN
          free_found := TRUE;
          EXIT;
        END_IF;
      END_IF;
    END_IF;
  END_FOR;

  (* — Pass 2: all occupied → mark ONE movable unit TO_AVOID — *)
  IF NOT free_found THEN
    FOR p := 0 TO MAX_STATIONS_PER_STEP - 1 DO
      next_stn := g_program[u].Steps[snap[u].CurStage].Stations[p];
      IF next_stn = 0 THEN
        EXIT;
      END_IF;
      IF next_stn >= MIN_StationIndex AND next_stn <= MAX_StationIndex THEN
        occ_uid := g_station_loc[next_stn].UnitId;
        IF occ_uid >= 1 AND occ_uid <= MAX_Units THEN
          IF NOT snap[occ_uid].HasBatch AND snap[occ_uid].Target = TO_NONE THEN
            avoid_uid := occ_uid;
            EXIT;
          END_IF;
        END_IF;
      END_IF;
    END_FOR;

    IF avoid_uid >= 1 THEN
      g_unit[avoid_uid].Target := TO_AVOID;
      snap[avoid_uid].Target     := TO_AVOID;  (* update snapshot *)
    END_IF;
  END_IF;
END_FOR;

(* ════════════════════════════════════════════════════════════
   Section 3 — TO_LOADING: route one empty unit to loading station
   ════════════════════════════════════════════════════════════
   When production is active and a loading/loading_unloading station
   is free, find ONE batchless USED unit with TO_NONE target.
   Priority: units NOT in buffer/storage first. *)
IF g_production_queue = 1 AND NOT has_loading THEN

  (* Check if any loading station is free *)
  load_free := FALSE;
  FOR stk := MIN_StationIndex TO MAX_StationIndex DO
    op := g_station[stk].StationType;
    IF (op = OP_LOADING OR op = OP_LOADING_UNLOADING)
       AND g_station_loc[stk].UnitId = 0 THEN
      load_free := TRUE;
      EXIT;
    END_IF;
  END_FOR;

  IF load_free THEN
    load_uid    := 0;
    load_in_buf := FALSE;
    FOR u := 1 TO MAX_Units DO
      IF snap[u].IsActive AND NOT snap[u].HasBatch
         AND snap[u].Target = TO_NONE AND snap[u].OnStation THEN
        IF snap[u].InBuffer THEN
          IF load_uid = 0 THEN
            load_uid    := u;
            load_in_buf := TRUE;
          END_IF;
        ELSE
          IF load_uid = 0 OR load_in_buf THEN
            load_uid    := u;
            load_in_buf := FALSE;
          END_IF;
        END_IF;
      END_IF;
    END_FOR;

    IF load_uid >= 1 THEN
      g_unit[load_uid].Target := TO_LOADING;
    END_IF;
  END_IF; (* load_free *)

END_IF; (* production_queue AND NOT has_loading *)

IF i_unit < 1 OR i_unit > MAX_Units THEN RETURN; END_IF;
IF ABS(i_amount) < 0.001 THEN RETURN; END_IF;

(* ── Shift schedule stages entry/exit times ── *)
sc := g_schedule[i_unit].StageCount;
FOR si := i_from_stage TO sc DO
  IF si >= 1 AND si <= 30 THEN
    g_schedule[i_unit].Stages[si].EntryTime :=
      g_schedule[i_unit].Stages[si].EntryTime + REAL_TO_LINT(i_amount);
    g_schedule[i_unit].Stages[si].ExitTime :=
      g_schedule[i_unit].Stages[si].ExitTime + REAL_TO_LINT(i_amount);
  END_IF;
END_FOR;

(* ── Shift matching tasks in all transporter queues ── *)
FOR ti := 1 TO MAX_Transporters DO
  FOR qi := 1 TO g_task[ti].Count DO
    IF g_task[ti].Queue[qi].Unit = i_unit
       AND g_task[ti].Queue[qi].Stage >= i_from_stage THEN
      g_task[ti].Queue[qi].StartTime :=
        g_task[ti].Queue[qi].StartTime + REAL_TO_LINT(i_amount);
      g_task[ti].Queue[qi].FinishTime :=
        g_task[ti].Queue[qi].FinishTime + REAL_TO_LINT(i_amount);
    END_IF;
  END_FOR;
END_FOR;

IF i_trans >= 1 AND i_trans <= 3 THEN
  t_start := i_trans;
  t_end   := i_trans;
ELSE
  t_start := 1;
  t_end   := 3;
END_IF;

FOR ti := t_start TO t_end DO
  ins_cnt := g_task[ti].Count;
  IF ins_cnt >= 2 THEN
    FOR ins_i := 2 TO ins_cnt DO
      tmp_task := g_task[ti].Queue[ins_i];
      ins_j := ins_i - 1;
      WHILE ins_j >= 1 AND g_task[ti].Queue[ins_j].StartTime > tmp_task.StartTime DO
        g_task[ti].Queue[ins_j + 1] := g_task[ti].Queue[ins_j];
        ins_j := ins_j - 1;
      END_WHILE;
      g_task[ti].Queue[ins_j + 1] := tmp_task;
    END_FOR;
  END_IF;
END_FOR;

IF (i_unit >= 1) AND (i_unit <= MAX_Units) THEN
  old_loc := g_unit[i_unit].location;

  (* --- Clear unit_id from old location (unified: transporter or station) --- *)
  IF (old_loc >= 1) AND (old_loc <= MAX_StationIndex) THEN
    g_station_loc[old_loc].UnitId     := 0;
    g_station_loc[old_loc].ChangeTime := g_time_s;
  END_IF;

  (* --- Update unit location --- *)
  g_unit[i_unit].location := i_location;

  (* --- Set unit_id on new location (unified: transporter or station) --- *)
  IF (i_location >= 1) AND (i_location <= MAX_StationIndex) THEN
    g_station_loc[i_location].UnitId     := i_unit;
    g_station_loc[i_location].ChangeTime := g_time_s;

    (* Station-specific: batch stage advance only when landing on a station *)
    IF (i_location >= MIN_StationIndex) THEN

    (* Advance batch stage if unit is USED with an active batch *)
    IF (g_unit[i_unit].Status = 1)  (* USED *)
       AND (g_batch[i_unit].BatchCode <> 0)
       AND (g_batch[i_unit].State = IN_PROCESS)
       AND (g_batch[i_unit].CurStage < MAX_STEPS_PER_PROGRAM) THEN
      g_batch[i_unit].CurStage := g_batch[i_unit].CurStage + 1;

      (* Stamp arrival time on new station — used by CalcSchedule for elapsed calculation *)
      g_batch[i_unit].StartTime := g_time_s;

      (* Update batch treatment times from program for the new stage *)
      IF (g_program[i_unit].ProgramId = g_batch[i_unit].ProgId)
         AND (g_program[i_unit].ProgramId > 0) THEN
        new_stg := g_batch[i_unit].CurStage;
        IF (new_stg >= 1) AND (new_stg <= MAX_STEPS_PER_PROGRAM) THEN
          g_batch[i_unit].MinTime := g_program[i_unit].Steps[new_stg - 1].MinTime;
          g_batch[i_unit].MaxTime := g_program[i_unit].Steps[new_stg - 1].MaxTime;
          g_batch[i_unit].CalTime := g_program[i_unit].Steps[new_stg - 1].CalTime;
        END_IF;
      END_IF;
    END_IF;

    (* NOT_PROCESSED batch on station: clear times so UI shows no progress bar *)
    IF (g_batch[i_unit].BatchCode <> 0)
       AND (g_batch[i_unit].State <> IN_PROCESS) THEN
      g_batch[i_unit].MinTime   := 0;
      g_batch[i_unit].CalTime   := 0;
      g_batch[i_unit].MaxTime   := 32000;  (* ~8.9 h cap, INT max safe *)
      g_batch[i_unit].StartTime := g_time_s;
    END_IF;

    (* Clear unit target after placement (NTT task done) *)
    IF g_unit[i_unit].Target <> 0 THEN
      g_unit[i_unit].Target := 0;  (* TO_NONE *)
    END_IF;

    END_IF; (* i_location >= MIN_StationIndex — station-specific block *)
  END_IF; (* i_location valid *)
END_IF;

o_trans := 0;
FOR ti := 1 TO MAX_Transporters DO
  IF o_trans = 0 THEN
    FOR ai := 1 TO 4 DO
      IF o_trans = 0 THEN
        area := g_cfg[ti].TaskArea[ai];
        IF area.MinLift > 0 OR area.MaxLift > 0 THEN
          can_lift := (i_lift_stn >= area.MinLift) AND (i_lift_stn <= area.MaxLift);
          IF i_sink_stn = 0 THEN
            IF can_lift THEN
              o_trans := ti;
            END_IF;
          ELSE
            can_sink := (i_sink_stn >= area.MinSink) AND (i_sink_stn <= area.MaxSink);
            IF can_lift AND can_sink THEN
              o_trans := ti;
            END_IF;
          END_IF;
        END_IF;
      END_IF;
    END_FOR;
  END_IF;
END_FOR;

o_has_conflict := FALSE;
o_conf_type    := 0;
o_deficit      := 0.0;
checked_count  := 0;

(* Count total tasks *)
total_tasks := 0;
FOR ti := 1 TO MAX_Transporters DO
  total_tasks := total_tasks + g_task[ti].Count;
END_FOR;
IF total_tasks = 0 THEN RETURN; END_IF;

(* ══════════════════════════════════════════════════════════════════════ *)
(* CHECK 1: TASK_SEQUENCE — per-transporter queue order (SWAP-safe)    *)
(* Iterates g_task[ti].Queue[] in queue order, NOT sorted by time.     *)
(* ══════════════════════════════════════════════════════════════════════ *)
FOR ti := 1 TO MAX_Transporters DO
  FOR qi := 1 TO g_task[ti].Count - 1 DO
    IF g_task[ti].Queue[qi].Unit > 0 AND g_task[ti].Queue[qi + 1].Unit > 0 THEN

      prev_sink := g_task[ti].Queue[qi].SinkStationTarget;
      next_lift := g_task[ti].Queue[qi + 1].LiftStationTarget;

      tmp_move := g_move[ti];
      travel_s := STC_CalcHorizontalTravel(i_from_stn := prev_sink, i_to_stn := next_lift, i_move := tmp_move);

      gap_s := LINT_TO_REAL(
        g_task[ti].Queue[qi + 1].StartTime - g_task[ti].Queue[qi].FinishTime
      );
      deficit_s := travel_s - gap_s;

      IF deficit_s > DEFICIT_TOL THEN
        o_has_conflict  := TRUE;
        o_conf_type     := 1;  (* TASK_SEQUENCE *)
        o_conf_unit     := g_task[ti].Queue[qi + 1].Unit;
        o_conf_stage    := g_task[ti].Queue[qi + 1].Stage;
        o_conf_trans    := ti;
        o_blocked_unit  := g_task[ti].Queue[qi].Unit;
        o_blocked_stage := g_task[ti].Queue[qi].Stage;
        o_deficit       := deficit_s;
        checked_count   := total_tasks;
        RETURN;
      END_IF;

    END_IF;
  END_FOR;
END_FOR;

(* ══════════════════════════════════════════════════════════════════════ *)
(* CHECK 2: TRANSPORTER_COLLISION — X+time overlap, different trans.   *)
(* Compares every task pair across different transporters.              *)
(* ══════════════════════════════════════════════════════════════════════ *)
FOR ti := 1 TO MAX_Transporters DO
  FOR qi := 1 TO g_task[ti].Count DO
    IF g_task[ti].Queue[qi].Unit > 0 THEN

      (* X range for task A *)
      l_idx := g_task[ti].Queue[qi].LiftStationTarget - 100;
      s_idx := g_task[ti].Queue[qi].SinkStationTarget - 100;
      IF l_idx >= 1 AND l_idx <= 30 THEN
        lift_x := DINT_TO_REAL(g_station[g_task[ti].Queue[qi].LiftStationTarget].XPosition);
      ELSE
        lift_x := 0.0;
      END_IF;
      IF s_idx >= 1 AND s_idx <= 30 THEN
        sink_x := DINT_TO_REAL(g_station[g_task[ti].Queue[qi].SinkStationTarget].XPosition);
      ELSE
        sink_x := 0.0;
      END_IF;
      IF lift_x < sink_x THEN
        x1_min := lift_x;
        x1_max := sink_x;
      ELSE
        x1_min := sink_x;
        x1_max := lift_x;
      END_IF;

      FOR tj := ti + 1 TO MAX_Transporters DO
        FOR qj := 1 TO g_task[tj].Count DO
          IF g_task[tj].Queue[qj].Unit > 0 THEN

            (* X range for task B *)
            l_idx2 := g_task[tj].Queue[qj].LiftStationTarget - 100;
            s_idx2 := g_task[tj].Queue[qj].SinkStationTarget - 100;
            IF l_idx2 >= 1 AND l_idx2 <= 30 THEN
              lift_x2 := DINT_TO_REAL(g_station[g_task[tj].Queue[qj].LiftStationTarget].XPosition);
            ELSE
              lift_x2 := 0.0;
            END_IF;
            IF s_idx2 >= 1 AND s_idx2 <= 30 THEN
              sink_x2 := DINT_TO_REAL(g_station[g_task[tj].Queue[qj].SinkStationTarget].XPosition);
            ELSE
              sink_x2 := 0.0;
            END_IF;
            IF lift_x2 < sink_x2 THEN
              x2_min := lift_x2;
              x2_max := sink_x2;
            ELSE
              x2_min := sink_x2;
              x2_max := lift_x2;
            END_IF;

            (* X overlap *)
            xo_start := x1_min;
            IF x2_min > xo_start THEN xo_start := x2_min; END_IF;
            xo_end := x1_max;
            IF x2_max < xo_end THEN xo_end := x2_max; END_IF;

            IF xo_start < xo_end THEN
              (* Time overlap *)
              to_start := g_task[ti].Queue[qi].StartTime;
              IF g_task[tj].Queue[qj].StartTime > to_start THEN
                to_start := g_task[tj].Queue[qj].StartTime;
              END_IF;
              to_end := g_task[ti].Queue[qi].FinishTime;
              IF g_task[tj].Queue[qj].FinishTime < to_end THEN
                to_end := g_task[tj].Queue[qj].FinishTime;
              END_IF;

              IF to_start < to_end THEN
                deficit_s := LINT_TO_REAL(to_end - to_start) + 2.0;
                o_has_conflict  := TRUE;
                o_conf_type     := 2;  (* TRANSPORTER_COLLISION *)
                o_conf_unit     := g_task[tj].Queue[qj].Unit;
                o_conf_stage    := g_task[tj].Queue[qj].Stage;
                o_conf_trans    := tj;
                o_blocked_unit  := g_task[ti].Queue[qi].Unit;
                o_blocked_stage := g_task[ti].Queue[qi].Stage;
                o_deficit       := deficit_s;
                checked_count   := total_tasks;
                RETURN;
              END_IF;
            END_IF;

          END_IF;
        END_FOR;
      END_FOR;

    END_IF;
  END_FOR;
END_FOR;

(* ══════════════════════════════════════════════════════════════════════ *)
(* CHECK 3: CROSS_TRANSPORTER_HANDOFF                                  *)
(* Same batch, consecutive stages on different transporters.           *)
(* Does the receiving transporter have time to reach handoff station?  *)
(*                                                                      *)
(* Conflict targets the DELIVERING task (current transporter);         *)
(* resolver will delay the preceding stage so the batch waits longer   *)
(* on the delivering transporter's side.                               *)
(* ══════════════════════════════════════════════════════════════════════ *)
FOR ti := 1 TO MAX_Transporters DO
  FOR qi := 1 TO g_task[ti].Count DO
    cur_unit  := g_task[ti].Queue[qi].Unit;
    cur_stage := g_task[ti].Queue[qi].Stage;
    IF cur_unit > 0 THEN

      (* Find next stage of same batch in a different transporter *)
      found_next := FALSE;
      FOR tj := 1 TO MAX_Transporters DO
        IF tj <> ti AND NOT found_next THEN
          FOR qj := 1 TO g_task[tj].Count DO
            IF NOT found_next THEN
              IF g_task[tj].Queue[qj].Unit = cur_unit
                 AND g_task[tj].Queue[qj].Stage = cur_stage + 1 THEN
                found_next := TRUE;

                (* Found handoff pair: ti delivers to sink, tj picks up *)
                (* Find receiver's (tj) previous task — latest finish before next task start *)
                has_recv_prev := FALSE;
                recv_prev_end  := 0;
                recv_prev_sink := 0;
                FOR rk := 1 TO g_task[tj].Count DO
                  IF rk <> qj THEN
                    IF g_task[tj].Queue[rk].FinishTime <= g_task[tj].Queue[qj].StartTime THEN
                      IF NOT has_recv_prev OR g_task[tj].Queue[rk].FinishTime > recv_prev_end THEN
                        has_recv_prev := TRUE;
                        recv_prev_end  := g_task[tj].Queue[rk].FinishTime;
                        recv_prev_sink := g_task[tj].Queue[rk].SinkStationTarget;
                      END_IF;
                    END_IF;
                  END_IF;
                END_FOR;

                IF has_recv_prev THEN
                  (* Travel from receiver's prev sink to handoff station (= ti's current sink) *)
                  recv_travel := STC_CalcHorizontalTravel(
                    i_from_stn := recv_prev_sink,
                    i_to_stn   := g_task[ti].Queue[qi].SinkStationTarget,
                    i_move     := g_move[tj]
                  );
                  recv_earliest := recv_prev_end + REAL_TO_LINT(recv_travel);
                  handoff_deficit := LINT_TO_REAL(
                    recv_earliest - g_task[ti].Queue[qi].FinishTime
                  );

                  IF handoff_deficit > DEFICIT_TOL THEN
                    o_has_conflict  := TRUE;
                    o_conf_type     := 3;  (* CROSS_TRANSPORTER_HANDOFF *)
                    (* Conflict on delivering task *)
                    o_conf_unit     := g_task[ti].Queue[qi].Unit;
                    o_conf_stage    := g_task[ti].Queue[qi].Stage;
                    o_conf_trans    := ti;
                    (* Blocked by receiver's previous task *)
                    o_blocked_unit  := g_task[tj].Queue[rk].Unit;
                    o_blocked_stage := g_task[tj].Queue[rk].Stage;
                    o_deficit       := handoff_deficit;
                    checked_count   := total_tasks;
                    RETURN;
                  END_IF;
                END_IF;
                (* If no recv prev task, receiver is idle → no handoff conflict *)

              END_IF;
            END_IF;
          END_FOR;
        END_IF;
      END_FOR;

    END_IF;
  END_FOR;
END_FOR;

(* No conflict found *)
checked_count := total_tasks;

(* -- Validate inputs -- *)
IF i_unit < 1 OR i_unit > MAX_Units THEN RETURN; END_IF;
IF i_trans < 1 OR i_trans > MAX_Transporters THEN RETURN; END_IF;

(* -- Read batch and unit data -- *)
cur_stage := g_batch[i_unit].CurStage;
location  := g_unit[i_unit].location;
is_on_stn := location >= 100;
out_count := 0;

(* -- Clear old schedule -- *)
FOR st := 1 TO 30 DO
  g_schedule[i_unit].Stages[st].station := 0;
  g_schedule[i_unit].Stages[st].EntryTime := 0;
  g_schedule[i_unit].Stages[st].ExitTime := 0;
  g_schedule[i_unit].Stages[st].MinTime := 0;
  g_schedule[i_unit].Stages[st].CalcTime := 0;
  g_schedule[i_unit].Stages[st].MaxTime := 0;
  g_schedule[i_unit].Stages[st].TransferTime := 0;
END_FOR;

(* -- Determine start stage -- *)
(* Waiting batch (state = NOT_PROCESSED): treat as stage 0 *)
IF g_batch[i_unit].State = 0 THEN
  cur_stage := 0;
END_IF;

(* If on transporter, start from next stage; if on station, from current *)
IF is_on_stn THEN
  start_st := cur_stage;
ELSE
  start_st := cur_stage + 1;
END_IF;

(* Force minimum stage 1 *)
IF start_st < 1 THEN
  start_st := 1;
END_IF;

(* -- Previous station (where transfer starts from) -- *)
IF is_on_stn THEN
  prev_stn := location;
ELSIF cur_stage >= 1 AND cur_stage <= 30 THEN
  (* On transporter: use previous stage station *)
  prev_stn := g_program[i_unit].Steps[cur_stage - 1].Stations[0];
ELSE
  prev_stn := 0;
END_IF;

(* -- prevExitTime: when next stage can begin -- *)
IF is_on_stn THEN
  (* Unit is on station: calculate remaining time *)
  calc_s := INT_TO_REAL(g_batch[i_unit].CurStage);
  (* For first stage, remaining time based on calc_time *)
  exit_t := i_time_s;
ELSE
  exit_t := i_time_s;
END_IF;

is_first := TRUE;

(* -- Prepend current location when unit needs pre-positioning -- *)
(* If unit is on a station that is NOT the first treatment station,
   insert it as schedule entry 0 (0 treatment time) so that
   CreateTasks generates a move-to-first-station task. *)
IF is_on_stn AND start_st >= 1 THEN
  stn_num := 0;
  FOR p := 0 TO 4 DO
    IF g_program[i_unit].Steps[start_st - 1].Stations[p] = location THEN
      stn_num := location;  (* flag: already on first treatment station *)
    END_IF;
  END_FOR;
  IF stn_num = 0 THEN
    out_count := out_count + 1;
    g_schedule[i_unit].Stages[out_count].station       := location;
    g_schedule[i_unit].Stages[out_count].EntryTime    := exit_t;
    g_schedule[i_unit].Stages[out_count].ExitTime     := exit_t;
    g_schedule[i_unit].Stages[out_count].MinTime      := 0;
    g_schedule[i_unit].Stages[out_count].CalcTime     := 0;
    g_schedule[i_unit].Stages[out_count].MaxTime      := 0;
    g_schedule[i_unit].Stages[out_count].TransferTime := 0;
    is_first := FALSE;
  END_IF;
END_IF;

(* ============================================================
   MAIN LOOP: Calculate schedule for each program stage
   ============================================================ *)
FOR st := start_st TO g_program[i_unit].StepCount DO

  (* Check if stage has valid stations — parallel selection *)
  cand_cnt := 0;
  FOR p := 0 TO 4 DO
    IF g_program[i_unit].Steps[st - 1].Stations[p] > 0 THEN
      cand_cnt := cand_cnt + 1;
      cand_arr[cand_cnt] := g_program[i_unit].Steps[st - 1].Stations[p];
      sched_occupied[cand_cnt] := FALSE;
      phys_occupied[cand_cnt] := FALSE;
    END_IF;
  END_FOR;

  (* No station means end of program *)
  IF cand_cnt = 0 THEN
    EXIT;
  END_IF;

  IF cand_cnt = 1 THEN
    chosen_stn := cand_arr[1];
  ELSE
    (* Read treatment times early — needed for time window estimate *)
    calc_s := DINT_TO_REAL(g_program[i_unit].Steps[st - 1].CalTime);

    (* Estimate this stage's time window *)
    tmp_move := g_move[i_trans];
    xfer_t := STC_CalcTransferTime(i_from_stn := prev_stn, i_to_stn := cand_arr[1], i_move := tmp_move);
    my_entry := exit_t + REAL_TO_LINT(xfer_t);
    my_exit  := my_entry + REAL_TO_LINT(calc_s);

    (* Check schedule overlap + physical occupation for each candidate *)
    FOR p := 1 TO cand_cnt DO
      FOR uj := 1 TO MAX_Units DO
        IF uj <> i_unit AND g_schedule[uj].StageCount > 0 THEN
          FOR sj := 1 TO g_schedule[uj].StageCount DO
            IF g_schedule[uj].Stages[sj].station = cand_arr[p] THEN
              ov_start := my_entry;
              IF g_schedule[uj].Stages[sj].EntryTime > ov_start THEN
                ov_start := g_schedule[uj].Stages[sj].EntryTime;
              END_IF;
              ov_end := my_exit;
              IF g_schedule[uj].Stages[sj].ExitTime < ov_end THEN
                ov_end := g_schedule[uj].Stages[sj].ExitTime;
              END_IF;
              IF ov_end > ov_start THEN
                sched_occupied[p] := TRUE;
              END_IF;
            END_IF;
          END_FOR;
        END_IF;
      END_FOR;

      (* Physical occupation *)
      FOR uj := 1 TO MAX_Units DO
        IF g_unit[uj].location = cand_arr[p] AND g_unit[uj].Status = 1 THEN
          phys_occupied[p] := TRUE;
        END_IF;
      END_FOR;
    END_FOR;

    (* Select best free station: longest idle = smallest change_time *)
    chosen_stn := 0;
    best_change_time := LINT#9999999999;
    FOR p := 1 TO cand_cnt DO
      IF NOT sched_occupied[p] AND NOT phys_occupied[p] THEN
        IF cand_arr[p] >= MIN_StationIndex AND cand_arr[p] <= MAX_StationIndex THEN
          IF g_station_loc[cand_arr[p]].ChangeTime < best_change_time THEN
            best_change_time := g_station_loc[cand_arr[p]].ChangeTime;
            chosen_stn := cand_arr[p];
          END_IF;
        END_IF;
      END_IF;
    END_FOR;

    (* Fallback: schedule-free only *)
    IF chosen_stn = 0 THEN
      FOR p := 1 TO cand_cnt DO
        IF NOT sched_occupied[p] AND chosen_stn = 0 THEN
          chosen_stn := cand_arr[p];
        END_IF;
      END_FOR;
    END_IF;

    (* Ultimate fallback: first candidate *)
    IF chosen_stn = 0 THEN
      chosen_stn := cand_arr[1];
    END_IF;
  END_IF;

  stn_num := chosen_stn;

  (* Read treatment times from program *)
  calc_s := DINT_TO_REAL(g_program[i_unit].Steps[st - 1].CalTime);
  min_s  := DINT_TO_REAL(g_program[i_unit].Steps[st - 1].MinTime);
  max_s  := DINT_TO_REAL(g_program[i_unit].Steps[st - 1].MaxTime);

  (* -- Calculate transfer time from prev_stn to stn_num -- *)
  tmp_move := g_move[i_trans];
  xfer_t := STC_CalcTransferTime(i_from_stn := prev_stn, i_to_stn := stn_num, i_move := tmp_move);

  (* -- Calculate entry and exit times -- *)
  IF is_first AND is_on_stn AND st = cur_stage THEN
    (* Batch is currently at this station *)
    entry_t := i_time_s;
    (* Remaining time: calc_time - elapsed since arrival *)
    IF g_batch[i_unit].StartTime > 0 THEN
      elapsed_s := LINT_TO_REAL(i_time_s - g_batch[i_unit].StartTime);
    ELSE
      elapsed_s := 0.0;
    END_IF;
    remain_s := calc_s - elapsed_s;
    IF remain_s < 1.0 THEN remain_s := 1.0; END_IF;
    exit_t := i_time_s + REAL_TO_LINT(remain_s);
  ELSIF is_first AND NOT is_on_stn THEN
    (* Batch is on transporter: entry = now (transfer in progress) *)
    entry_t := exit_t;
    exit_t  := entry_t + REAL_TO_LINT(calc_s);
  ELSE
    (* Normal stage: entry = prev exit + transfer *)
    entry_t := exit_t + REAL_TO_LINT(xfer_t);
    exit_t  := entry_t + REAL_TO_LINT(calc_s);
  END_IF;

  (* -- Write to schedule -- *)
  out_count := out_count + 1;
  IF out_count <= 30 THEN
    g_schedule[i_unit].Stages[out_count].station       := stn_num;
    g_schedule[i_unit].Stages[out_count].EntryTime    := entry_t;
    g_schedule[i_unit].Stages[out_count].ExitTime     := exit_t;
    g_schedule[i_unit].Stages[out_count].MinTime      := REAL_TO_DINT(min_s);
    g_schedule[i_unit].Stages[out_count].CalcTime     := REAL_TO_DINT(calc_s);
    g_schedule[i_unit].Stages[out_count].MaxTime      := REAL_TO_DINT(max_s);
    g_schedule[i_unit].Stages[out_count].TransferTime := REAL_TO_DINT(xfer_t);
  END_IF;

  (* -- Update for next iteration -- *)
  prev_stn := stn_num;
  is_first := FALSE;

END_FOR;

g_schedule[i_unit].StageCount := out_count;

IF i_unit < 1 OR i_unit > MAX_Units THEN RETURN; END_IF;

sc := g_schedule[i_unit].StageCount;
IF sc < 2 THEN RETURN; END_IF;

(* CalcSchedule already builds a schedule starting from the batch's
   current stage (and prepends the unit's current location when needed).
   No skip logic needed here — every consecutive pair is a valid task. *)

(* Loop through consecutive stage pairs *)
FOR si := 1 TO sc - 1 DO
  lift_stn := g_schedule[i_unit].Stages[si].station;
  sink_stn := g_schedule[i_unit].Stages[si + 1].station;

  IF lift_stn > 0 AND sink_stn > 0 THEN
    (* -- Find transporter via task_area matching -- *)
    fb_find(i_lift_stn := lift_stn, i_sink_stn := sink_stn);
    tid := fb_find.o_trans;

    (* -- Append task to transporter queue -- *)
    IF tid >= 1 AND tid <= 3 THEN
      qi := g_task[tid].Count + 1;
      IF qi <= MAX_TASK_QUEUE THEN
        g_task[tid].Queue[qi].Unit         := i_unit;
        g_task[tid].Queue[qi].Stage        := si - 1;  (* schedule idx 1=stage0, 2=stage1, ... *)
        g_task[tid].Queue[qi].LiftStationTarget := lift_stn;
        g_task[tid].Queue[qi].SinkStationTarget := sink_stn;
        g_task[tid].Queue[qi].StartTime   := g_schedule[i_unit].Stages[si].ExitTime;
        g_task[tid].Queue[qi].FinishTime  := g_schedule[i_unit].Stages[si + 1].EntryTime;
        g_task[tid].Queue[qi].CalcTime    := g_schedule[i_unit].Stages[si].CalcTime;
        g_task[tid].Queue[qi].MinTime     := g_schedule[i_unit].Stages[si].MinTime;
        g_task[tid].Queue[qi].MaxTime     := g_schedule[i_unit].Stages[si].MaxTime;
        g_task[tid].Count := qi;
      END_IF;
    END_IF;
  END_IF;
END_FOR;

FOR ui := 1 TO MAX_Units DO
  tgt := g_unit[ui].Target;
  loc := g_unit[ui].location;

  (* Skip: no target, not on station.
     TO_PROCESS(3) is only handled here when batch state = NOT_PROCESSED
     (loaded unit waiting for processing → route to loaded-buffer). *)
  IF tgt >= 1 AND tgt <= 5 AND loc >= 100 THEN

    (* TO_PROCESS with batch already IN_PROCESS or later → skip (handled by schedule) *)
    IF tgt = 3 AND (g_batch[ui].BatchCode = 0 OR g_batch[ui].State <> 0) THEN
      CONTINUE;
    END_IF;

    (* Skip if unit already has a pending task in any queue or is being transported *)
    already := FALSE;
    FOR ti := 1 TO MAX_Transporters DO
      IF NOT already THEN
        (* Being transported right now? *)
        IF g_transporter[ti].Phase > 0 AND g_station_loc[ti].UnitId = ui THEN
          already := TRUE;
        END_IF;
        (* In any task queue? *)
        FOR qi2 := 1 TO g_task[ti].Count DO
          IF NOT already THEN
            IF g_task[ti].Queue[qi2].Unit = ui THEN
              already := TRUE;
            END_IF;
          END_IF;
        END_FOR;
      END_IF;
    END_FOR;

    IF NOT already THEN

    (* Try each transporter — not just the first covering one *)
    done := FALSE;
    FOR cov_t := 1 TO MAX_Transporters DO
      IF NOT done THEN

      (* Check coverage: transporter task_area covers this station *)
      covers := FALSE;
      FOR ai := 1 TO 4 DO
        IF NOT covers THEN
          IF g_cfg[cov_t].TaskArea[ai].MinLift > 0 OR g_cfg[cov_t].TaskArea[ai].MaxLift > 0 THEN
            IF loc >= g_cfg[cov_t].TaskArea[ai].MinLift AND loc <= g_cfg[cov_t].TaskArea[ai].MaxLift THEN
              covers := TRUE;
            END_IF;
          END_IF;
        END_IF;
      END_FOR;

      IF covers AND g_transporter[cov_t].IsActive
         AND (g_transporter[cov_t].Phase = 0 OR tgt = 5) THEN

        (* ── Resolve NTT index ── *)
        (* TO_BUFFER(2) maps to 6/7/8 depending on batch state *)
        (* TO_PROCESS(3) with NOT_PROCESSED batch → loaded buffer (7) *)
        IF tgt = 2 THEN
          IF g_batch[ui].BatchCode = 0 THEN
            ntt_idx := 6;  (* empty buffer — no batch *)
          ELSIF g_batch[ui].State = 2 THEN
            ntt_idx := 8;  (* processed buffer — batch PROCESSED *)
          ELSE
            ntt_idx := 7;  (* loaded buffer — batch NOT_PROCESSED or IN_PROCESS *)
          END_IF;
        ELSIF tgt = 3 THEN
          ntt_idx := 7;    (* TO_PROCESS + NOT_PROCESSED → loaded buffer *)
        ELSE
          ntt_idx := tgt;  (* other targets use their code directly *)
        END_IF;

        (* Get destination descriptor for this target + transporter *)
        dest := g_ntt[cov_t].Target[ntt_idx];

        (* ── Classify current location ── *)
        on_primary := FALSE;
        FOR si := 1 TO dest.StationCount DO
          IF dest.Stations[si] = loc THEN
            on_primary := TRUE;
          END_IF;
        END_FOR;

        (* Already on a primary station → no move needed *)
        IF NOT on_primary THEN

          on_fallback := FALSE;
          FOR si := 1 TO dest.FallbackCount DO
            IF dest.FallbackStations[si] = loc THEN
              on_fallback := TRUE;
            END_IF;
          END_FOR;

          (* Check if any primary station is free *)
          primary_free := FALSE;
          FOR si := 1 TO dest.StationCount DO
            stn := dest.Stations[si];
            IF stn <> loc AND stn >= MIN_StationIndex AND stn <= MAX_StationIndex THEN
              stn_free := TRUE;
              FOR uj := 1 TO MAX_Units DO
                IF g_unit[uj].location = stn AND g_unit[uj].Status = 1 THEN
                  stn_free := FALSE;
                END_IF;
              END_FOR;
              IF stn_free THEN
                primary_free := TRUE;
              END_IF;
            END_IF;
          END_FOR;

          dest_stn := 0;

          IF on_fallback AND NOT primary_free THEN
            (* On fallback, no primary free → stay put, don't bounce *)
            dest_stn := 0;
          ELSIF on_fallback AND primary_free THEN
            (* On fallback, primary is free → move to primary *)
            FOR si := 1 TO dest.StationCount DO
              IF dest_stn = 0 THEN
                stn := dest.Stations[si];
                IF stn <> loc AND stn >= MIN_StationIndex AND stn <= MAX_StationIndex THEN
                  stn_free := TRUE;
                  FOR uj := 1 TO MAX_Units DO
                    IF g_unit[uj].location = stn AND g_unit[uj].Status = 1 THEN
                      stn_free := FALSE;
                    END_IF;
                  END_FOR;
                  IF stn_free THEN
                    dest_stn := stn;
                  END_IF;
                END_IF;
              END_IF;
            END_FOR;
          ELSE
            (* Not on any known destination → full search: primary then fallback *)
            FOR si := 1 TO dest.StationCount DO
              IF dest_stn = 0 THEN
                stn := dest.Stations[si];
                IF stn <> loc AND stn >= MIN_StationIndex AND stn <= MAX_StationIndex THEN
                  stn_free := TRUE;
                  FOR uj := 1 TO MAX_Units DO
                    IF g_unit[uj].location = stn AND g_unit[uj].Status = 1 THEN
                      stn_free := FALSE;
                    END_IF;
                  END_FOR;
                  IF stn_free THEN
                    dest_stn := stn;
                  END_IF;
                END_IF;
              END_IF;
            END_FOR;

            IF dest_stn = 0 THEN
              FOR si := 1 TO dest.FallbackCount DO
                IF dest_stn = 0 THEN
                  stn := dest.FallbackStations[si];
                  IF stn <> loc AND stn >= MIN_StationIndex AND stn <= MAX_StationIndex THEN
                    stn_free := TRUE;
                    FOR uj := 1 TO MAX_Units DO
                      IF g_unit[uj].location = stn AND g_unit[uj].Status = 1 THEN
                        stn_free := FALSE;
                      END_IF;
                    END_FOR;
                    IF stn_free THEN
                      dest_stn := stn;
                    END_IF;
                  END_IF;
                END_IF;
              END_FOR;
            END_IF;
          END_IF;

          IF dest_stn > 0 THEN
            (* Calculate timing *)
            tmp_move := g_move[cov_t];
            xfer_s := STC_CalcTransferTime(i_from_stn := loc, i_to_stn := dest_stn, i_move := tmp_move);

            task_start := i_time_s;
            task_end   := task_start + REAL_TO_LINT(xfer_s);
            ntt_duration := task_end - task_start;

            (* ── Current-slot check: NTT fits only in the CURRENT idle slot ──
               Like JS: find the slot where start <= now < end, check totalTime
               fits. NTT is never placed into future slots — only "right now". *)
            slot_ok := FALSE;

            IF g_task[cov_t].Count = 0 THEN
              (* No existing tasks → NTT always fits *)
              slot_ok := TRUE;
            ELSE
              (* Current slot = time from NOW until first queued task starts.
                 NTT must fit: task_end + travel_to_next_lift <= queue[1].StartTime *)
              IF g_task[cov_t].Queue[1].StartTime > task_start THEN
                slot_start := task_start;
                slot_end   := g_task[cov_t].Queue[1].StartTime;
                (* Travel from NTT sink to first task's lift *)
                travel_from_sink := STC_CalcHorizontalTravel(
                  i_from_stn := dest_stn,
                  i_to_stn   := g_task[cov_t].Queue[1].LiftStationTarget,
                  i_move     := g_move[cov_t]
                );
                latest_end := slot_end - REAL_TO_LINT(travel_from_sink) - 1;
                IF task_start >= slot_start AND task_end <= latest_end THEN
                  slot_ok := TRUE;
                END_IF;
              END_IF;
            END_IF;

            IF NOT slot_ok THEN
              (* Exception: if the next queued task's sink station is where
                 this NTT unit sits, we MUST move it first or we deadlock.
                 Force-insert; future scheduling will re-stabilize the list. *)
              IF g_task[cov_t].Count > 0
                 AND g_task[cov_t].Queue[1].SinkStationTarget = loc THEN
                slot_ok := TRUE;  (* force — deadlock prevention *)
              ELSE
                dest_stn := 0;  (* NTT doesn't fit → skip *)
              END_IF;
            END_IF;
          END_IF;

          IF dest_stn > 0 THEN
            (* Insert as FIRST task — shift existing tasks down *)
            IF g_task[cov_t].Count < MAX_TASK_QUEUE THEN
              (* Shift queue[1..Count] → queue[2..Count+1] *)
              FOR sh := g_task[cov_t].Count TO 1 BY -1 DO
                g_task[cov_t].Queue[sh + 1] := g_task[cov_t].Queue[sh];
              END_FOR;
              g_task[cov_t].Queue[1].Unit         := ui;
              g_task[cov_t].Queue[1].Stage        := 0;  (* no program stage *)
              g_task[cov_t].Queue[1].LiftStationTarget := loc;
              g_task[cov_t].Queue[1].SinkStationTarget := dest_stn;
              g_task[cov_t].Queue[1].StartTime   := task_start;
              g_task[cov_t].Queue[1].FinishTime  := task_end;
              g_task[cov_t].Queue[1].CalcTime    := 0;
              g_task[cov_t].Queue[1].MinTime     := 0;
              g_task[cov_t].Queue[1].MaxTime     := 0;
              g_task[cov_t].Count := g_task[cov_t].Count + 1;
              done := TRUE;
            END_IF;
          END_IF;

        END_IF; (* NOT on_primary *)

      END_IF; (* covers + idle *)

      END_IF; (* NOT done *)
    END_FOR; (* transporter loop *)

    END_IF; (* NOT already *)

  END_IF; (* valid target *)
END_FOR;

o_solved      := FALSE;
o_total_delay := 0.0;
o_total_adv   := 0.0;
remain        := i_deficit;

IF remain <= 0.1 THEN
  o_solved := TRUE;
  RETURN;
END_IF;

(* ══════ Lock check: is blocked stage locked DELAY? (cannot ADVANCE) ══════ *)
is_locked_adv := FALSE;
FOR lock_i := 1 TO io_lock_cnt DO
  IF io_locks[lock_i].Unit = i_blocked_unit
     AND io_locks[lock_i].Stage = i_blocked_stage
     AND io_locks[lock_i].Direction = 2 THEN  (* 2=DELAY *)
    is_locked_adv := TRUE;
  END_IF;
END_FOR;

(* ══════ Lock check: is conf stage locked ADVANCE? (cannot DELAY) ══════ *)
is_locked_del := FALSE;
FOR lock_i := 1 TO io_lock_cnt DO
  IF io_locks[lock_i].Unit = i_conf_unit
     AND io_locks[lock_i].Stage = i_conf_stage
     AND io_locks[lock_i].Direction = 1 THEN  (* 1=ADVANCE *)
    is_locked_del := TRUE;
  END_IF;
END_FOR;

can_advance := NOT is_locked_adv;
can_delay   := NOT is_locked_del;

(* ══════ Calculate chain flex DOWN for blocked batch ══════ *)
(* Sum of flex_down (calc_time - min_time) from stage 1 to blocked_stage *)
chain_flex_down := 0.0;
IF can_advance AND i_blocked_unit >= 1 AND i_blocked_unit <= MAX_Units THEN
  sc := g_schedule[i_blocked_unit].StageCount;
  FOR si := 1 TO sc DO
    IF si <= i_blocked_stage THEN
      stage_flex := DINT_TO_REAL(g_schedule[i_blocked_unit].Stages[si].CalcTime
                  - g_schedule[i_blocked_unit].Stages[si].MinTime);
      IF stage_flex > 0.0 THEN
        chain_flex_down := chain_flex_down + stage_flex;
      END_IF;
    END_IF;
  END_FOR;
END_IF;

(* ══════ Calculate chain flex UP for conflict batch ══════ *)
(* Sum of flex_up (max_time - calc_time) from stage 1 to conf_stage *)
chain_flex_up := 0.0;
IF can_delay AND i_conf_unit >= 1 AND i_conf_unit <= MAX_Units THEN
  sc := g_schedule[i_conf_unit].StageCount;
  FOR si := 1 TO sc DO
    IF si <= i_conf_stage THEN
      stage_flex := DINT_TO_REAL(g_schedule[i_conf_unit].Stages[si].MaxTime
                  - g_schedule[i_conf_unit].Stages[si].CalcTime);
      IF stage_flex > 0.0 THEN
        chain_flex_up := chain_flex_up + stage_flex;
      END_IF;
    END_IF;
  END_FOR;
END_IF;

(* Effective flex considering locks *)
IF can_advance THEN eff_adv := chain_flex_down; ELSE eff_adv := 0.0; END_IF;
IF can_delay   THEN eff_del := chain_flex_up;   ELSE eff_del := 0.0; END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PRIORITY 1: CHAIN_BACKWARD — advance blocked batch           *)
(* Walk backward from blocked_stage, reduce calc_time per stage *)
(* ══════════════════════════════════════════════════════════════ *)
IF can_advance AND chain_flex_down >= remain THEN
  walk_remain := remain;
  sc := g_schedule[i_blocked_unit].StageCount;

  (* Walk from blocked_stage backward to stage 1 *)
  FOR si := i_blocked_stage TO 1 BY -1 DO
    IF si >= 1 AND si <= sc AND walk_remain > 0.1 THEN
      walk_flex := DINT_TO_REAL(g_schedule[i_blocked_unit].Stages[si].CalcTime
                  - g_schedule[i_blocked_unit].Stages[si].MinTime);
      IF walk_flex < 0.0 THEN walk_flex := 0.0; END_IF;

      IF walk_flex > 0.1 THEN
        (* Cap: 90% if on stage, 50% otherwise *)
        IF g_batch[i_blocked_unit].CurStage = si THEN
          walk_cap := 0.9;
        ELSE
          walk_cap := 0.5;
        END_IF;
        walk_amount := walk_flex * walk_cap;
        IF walk_amount > walk_remain THEN walk_amount := walk_remain; END_IF;

        (* Apply: reduce calc_time + shift subsequent stages *)
        g_schedule[i_blocked_unit].Stages[si].CalcTime :=
          g_schedule[i_blocked_unit].Stages[si].CalcTime - REAL_TO_DINT(walk_amount);
        g_schedule[i_blocked_unit].Stages[si].ExitTime :=
          g_schedule[i_blocked_unit].Stages[si].ExitTime - REAL_TO_LINT(walk_amount);
        fb_shift(i_unit := i_blocked_unit, i_from_stage := si + 1, i_amount := -walk_amount);

        walk_remain := walk_remain - walk_amount;
        o_total_adv := o_total_adv + walk_amount;
      END_IF;
    END_IF;
  END_FOR;

  remain := remain - o_total_adv;

  (* Record lock: ADVANCE on blocked stage *)
  IF io_lock_cnt < 50 THEN
    io_lock_cnt := io_lock_cnt + 1;
    io_locks[io_lock_cnt].Unit := i_blocked_unit;
    io_locks[io_lock_cnt].Stage := i_blocked_stage;
    io_locks[io_lock_cnt].Direction := 1;  (* 1=ADVANCE *)
  END_IF;

  IF remain <= 0.1 THEN
    o_solved := TRUE;
    RETURN;
  END_IF;
END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PRIORITY 2: CHAIN_FORWARD — delay conflict batch             *)
(* Walk backward from conf_stage, increase calc_time per stage  *)
(* ══════════════════════════════════════════════════════════════ *)
IF can_delay AND chain_flex_up >= remain THEN
  walk_remain := remain;
  sc := g_schedule[i_conf_unit].StageCount;

  FOR si := i_conf_stage TO 1 BY -1 DO
    IF si >= 1 AND si <= sc AND walk_remain > 0.1 THEN
      walk_flex := DINT_TO_REAL(g_schedule[i_conf_unit].Stages[si].MaxTime
                  - g_schedule[i_conf_unit].Stages[si].CalcTime);
      IF walk_flex < 0.0 THEN walk_flex := 0.0; END_IF;

      IF walk_flex > 0.1 THEN
        IF g_batch[i_conf_unit].CurStage = si THEN
          walk_cap := 0.9;
        ELSE
          walk_cap := 0.5;
        END_IF;
        walk_amount := walk_flex * walk_cap;
        IF walk_amount > walk_remain THEN walk_amount := walk_remain; END_IF;

        g_schedule[i_conf_unit].Stages[si].CalcTime :=
          g_schedule[i_conf_unit].Stages[si].CalcTime + REAL_TO_DINT(walk_amount);
        g_schedule[i_conf_unit].Stages[si].ExitTime :=
          g_schedule[i_conf_unit].Stages[si].ExitTime + REAL_TO_LINT(walk_amount);
        fb_shift(i_unit := i_conf_unit, i_from_stage := si + 1, i_amount := walk_amount);

        walk_remain := walk_remain - walk_amount;
        o_total_delay := o_total_delay + walk_amount;
      END_IF;
    END_IF;
  END_FOR;

  remain := remain - o_total_delay;

  (* Record lock: DELAY on conf stage *)
  IF io_lock_cnt < 50 THEN
    io_lock_cnt := io_lock_cnt + 1;
    io_locks[io_lock_cnt].Unit := i_conf_unit;
    io_locks[io_lock_cnt].Stage := i_conf_stage;
    io_locks[io_lock_cnt].Direction := 2;  (* 2=DELAY *)
  END_IF;

  IF remain <= 0.1 THEN
    o_solved := TRUE;
    RETURN;
  END_IF;
END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PRIORITY 3: CHAIN_COMBINED — use both backward + forward     *)
(* First consume advance flex, then delay flex for the rest     *)
(* ══════════════════════════════════════════════════════════════ *)
IF eff_adv + eff_del >= remain THEN
  (* Distribute: advance first, delay for remainder *)
  use_adv := eff_adv;
  IF use_adv > remain THEN use_adv := remain; END_IF;
  use_del := remain - use_adv;
  IF use_del > eff_del THEN
    use_del := eff_del;
    use_adv := remain - use_del;
  END_IF;

  (* Apply ADVANCE portion *)
  IF can_advance AND use_adv > 0.1 THEN
    walk_remain := use_adv;
    sc := g_schedule[i_blocked_unit].StageCount;
    FOR si := i_blocked_stage TO 1 BY -1 DO
      IF si >= 1 AND si <= sc AND walk_remain > 0.1 THEN
        walk_flex := DINT_TO_REAL(g_schedule[i_blocked_unit].Stages[si].CalcTime
                  - g_schedule[i_blocked_unit].Stages[si].MinTime);
        IF walk_flex < 0.0 THEN walk_flex := 0.0; END_IF;
        IF walk_flex > 0.1 THEN
          IF g_batch[i_blocked_unit].CurStage = si THEN walk_cap := 0.9; ELSE walk_cap := 0.5; END_IF;
          walk_amount := walk_flex * walk_cap;
          IF walk_amount > walk_remain THEN walk_amount := walk_remain; END_IF;
          g_schedule[i_blocked_unit].Stages[si].CalcTime :=
          g_schedule[i_blocked_unit].Stages[si].CalcTime - REAL_TO_DINT(walk_amount);
          g_schedule[i_blocked_unit].Stages[si].ExitTime :=
            g_schedule[i_blocked_unit].Stages[si].ExitTime - REAL_TO_LINT(walk_amount);
          fb_shift(i_unit := i_blocked_unit, i_from_stage := si + 1, i_amount := -walk_amount);
          walk_remain := walk_remain - walk_amount;
          o_total_adv := o_total_adv + walk_amount;
        END_IF;
      END_IF;
    END_FOR;

    IF io_lock_cnt < 50 THEN
      io_lock_cnt := io_lock_cnt + 1;
      io_locks[io_lock_cnt].Unit := i_blocked_unit;
      io_locks[io_lock_cnt].Stage := i_blocked_stage;
      io_locks[io_lock_cnt].Direction := 1;
    END_IF;
  END_IF;

  (* Apply DELAY portion *)
  IF can_delay AND use_del > 0.1 THEN
    walk_remain := use_del;
    sc := g_schedule[i_conf_unit].StageCount;
    FOR si := i_conf_stage TO 1 BY -1 DO
      IF si >= 1 AND si <= sc AND walk_remain > 0.1 THEN
        walk_flex := DINT_TO_REAL(g_schedule[i_conf_unit].Stages[si].MaxTime
                  - g_schedule[i_conf_unit].Stages[si].CalcTime);
        IF walk_flex < 0.0 THEN walk_flex := 0.0; END_IF;
        IF walk_flex > 0.1 THEN
          IF g_batch[i_conf_unit].CurStage = si THEN walk_cap := 0.9; ELSE walk_cap := 0.5; END_IF;
          walk_amount := walk_flex * walk_cap;
          IF walk_amount > walk_remain THEN walk_amount := walk_remain; END_IF;
          g_schedule[i_conf_unit].Stages[si].CalcTime :=
          g_schedule[i_conf_unit].Stages[si].CalcTime + REAL_TO_DINT(walk_amount);
          g_schedule[i_conf_unit].Stages[si].ExitTime :=
            g_schedule[i_conf_unit].Stages[si].ExitTime + REAL_TO_LINT(walk_amount);
          fb_shift(i_unit := i_conf_unit, i_from_stage := si + 1, i_amount := walk_amount);
          walk_remain := walk_remain - walk_amount;
          o_total_delay := o_total_delay + walk_amount;
        END_IF;
      END_IF;
    END_FOR;

    IF io_lock_cnt < 50 THEN
      io_lock_cnt := io_lock_cnt + 1;
      io_locks[io_lock_cnt].Unit := i_conf_unit;
      io_locks[io_lock_cnt].Stage := i_conf_stage;
      io_locks[io_lock_cnt].Direction := 2;
    END_IF;
  END_IF;

  remain := remain - o_total_adv - o_total_delay;
  IF remain <= 0.1 THEN
    o_solved := TRUE;
    RETURN;
  END_IF;
END_IF;

(* If not solved, partial resolution was applied *)

IF NOT i_run THEN
  phase := 0;
  o_phase := 0;
  RETURN;
END_IF;

next_phase := phase;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 0: STOPPED — wait for i_run                            *)
(* ══════════════════════════════════════════════════════════════ *)
IF phase = 0 THEN
  next_phase := 1;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 1: INIT — collect active batches                       *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 1 THEN
  fb_collect(i_mode := 0);
  batch_count := fb_collect.o_count;
  FOR bi := 1 TO batch_count DO
    batch_list[bi] := fb_collect.o_list[bi];
  END_FOR;
  o_batch_cnt := batch_count;
  conflict_iter := 0;
  locks_initialized := FALSE;

  IF batch_count = 0 THEN
    (* No active batches — still run no-treatment tasks *)
    next_phase := 2204;
  ELSE
    next_phase := 2;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2: NO_TREATMENT_STATES — update unit/batch states      *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2 THEN
  fb_notrt_st();
  next_phase := 1000;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 1000: SCHEDULE_START                                   *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 1000 THEN
  batch_idx := 1;
  next_phase := 1001;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 1001..1000+MAX_Units: SCHEDULE per batch (one per tick) *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase >= 1001 AND phase <= 1000 + MAX_Units THEN
  IF batch_idx <= batch_count THEN
    ui := batch_list[batch_idx];

    (* Find transporter for this unit — first one with matching task_area *)
    fb_find(i_lift_stn := g_unit[ui].location, i_sink_stn := 0);
    sched_trans := fb_find.o_trans;
    IF sched_trans = 0 THEN sched_trans := 1; END_IF;  (* fallback default *)

    fb_calc(i_unit := ui, i_trans := sched_trans, i_time_s := i_time_s);

    batch_idx := batch_idx + 1;
    IF batch_idx <= batch_count THEN
      next_phase := phase + 1;
    ELSE
      next_phase := 1900;
    END_IF;
  ELSE
    next_phase := 1900;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 1900: SCHEDULE_DONE                                    *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 1900 THEN
  next_phase := 2000;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2000: TASKS_START — clear all task queues              *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2000 THEN
  fb_clear();
  batch_idx := 1;
  next_phase := 2001;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2001..2000+MAX_Units: CREATE_TASKS per batch (one per tick) *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase >= 2001 AND phase <= 2000 + MAX_Units THEN
  IF batch_idx <= batch_count THEN
    ui := batch_list[batch_idx];
    fb_create(i_unit := ui);
    batch_idx := batch_idx + 1;
    IF batch_idx <= batch_count THEN
      next_phase := phase + 1;
    ELSE
      next_phase := 2200;
    END_IF;
  ELSE
    next_phase := 2200;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2200: TASKS_SORT — insertion sort each queue by time   *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2200 THEN
  fb_sort(i_trans := 0);
  (* Initialize locks once per scheduler cycle *)
  IF NOT locks_initialized THEN
    lock_cnt := 0;
    FOR bi := 1 TO 50 DO
      locks[bi].Unit := 0;
      locks[bi].Stage := 0;
      locks[bi].Direction := 0;
    END_FOR;
    locks_initialized := TRUE;
  END_IF;
  next_phase := 2201;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2201: TASKS_SWAP                                       *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2201 THEN
  fb_swap();
  next_phase := 2202;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2202: TASKS_ANALYZE                                    *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2202 THEN
  fb_analyze();
  o_conflict := fb_analyze.o_has_conflict;
  IF fb_analyze.o_has_conflict THEN
    next_phase := 2203;
  ELSE
    next_phase := 2204;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2203: TASKS_RESOLVE                                    *)
(* One conflict per cycle → recalculate                         *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2203 THEN
  fb_resolve(
    i_conf_unit     := fb_analyze.o_conf_unit,
    i_conf_stage    := fb_analyze.o_conf_stage,
    i_conf_trans    := fb_analyze.o_conf_trans,
    i_blocked_unit  := fb_analyze.o_blocked_unit,
    i_blocked_stage := fb_analyze.o_blocked_stage,
    i_deficit       := fb_analyze.o_deficit,
    io_locks        := locks,
    io_lock_cnt     := lock_cnt
  );

  conflict_iter := conflict_iter + 1;

  IF conflict_iter >= MAX_CONFLICT_ITER THEN
    (* Max iterations reached — accept partial solution *)
    next_phase := 2204;
  ELSE
    (* Re-analyze: SORT → SWAP → ANALYZE again *)
    next_phase := 2200;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2204: TASKS_NO_TREATMENT                               *)
(* Task list is stable (no conflicts). Create unit-target tasks *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2204 THEN
  fb_notrt(i_time_s := i_time_s);
  o_conflict := FALSE;
  next_phase := 10000;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 10000: READY — cycle complete                          *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 10000 THEN
  (* Count total tasks *)
  total_tasks := 0;
  FOR ti := 1 TO MAX_Transporters DO
    total_tasks := total_tasks + g_task[ti].Count;
  END_FOR;
  o_task_cnt := total_tasks;
  next_phase := 10100;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 10100: CHECK_DEP_PENDING — DEP activated a batch       *)
(* Copy pending data to globals and trigger full recalculation  *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 10100 THEN
  IF g_dep_pending.Valid THEN
    (* Apply DEP's pending data: programs + schedules + stage change *)
    FOR ui := 1 TO MAX_Units DO
      g_program[ui]  := g_dep_pending.Programs[ui];
      g_schedule[ui] := g_dep_pending.Schedule[ui];
    END_FOR;
    IF g_dep_pending.BatchUnit >= 1 AND g_dep_pending.BatchUnit <= MAX_Units THEN
      g_batch[g_dep_pending.BatchUnit].CurStage   := g_dep_pending.BatchStage;
      g_batch[g_dep_pending.BatchUnit].State        := g_dep_pending.BatchState;
      g_batch[g_dep_pending.BatchUnit].StartTime   := g_dep_pending.TimeStamp;
      g_batch[g_dep_pending.BatchUnit].MinTime     := g_dep_pending.BatchMinTime;
      g_batch[g_dep_pending.BatchUnit].MaxTime     := g_dep_pending.BatchMaxTime;
      g_batch[g_dep_pending.BatchUnit].CalTime     := g_dep_pending.BatchCalTime;
    END_IF;
    g_dep_pending.Valid := FALSE;
    (* Full recalculation with new data *)
    next_phase := 1;
  ELSE
    next_phase := 10110;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 10110: RESTART — begin new cycle                       *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 10110 THEN
  cycle_count := cycle_count + 1;
  o_cycle_cnt := cycle_count;
  next_phase := 1;  (* back to INIT *)

(* ══════════════════════════════════════════════════════════════ *)
(* Unknown phase → reset to INIT                                *)
(* ══════════════════════════════════════════════════════════════ *)
ELSE
  next_phase := 1;
END_IF;

(* ── Phase assignment at end of scan ── *)
phase := next_phase;
o_phase := phase;

o_swap_count := 0;

FOR ti := 1 TO MAX_Transporters DO
  cnt := g_task[ti].Count;
  IF cnt >= 2 THEN
    FOR qi := 1 TO cnt - 1 DO
      (* Check: different units AND prev.sink == next.lift *)
      IF g_task[ti].Queue[qi].Unit <> g_task[ti].Queue[qi + 1].Unit
         AND g_task[ti].Queue[qi].SinkStationTarget = g_task[ti].Queue[qi + 1].LiftStationTarget THEN
        (* Swap *)
        tmp := g_task[ti].Queue[qi];
        g_task[ti].Queue[qi] := g_task[ti].Queue[qi + 1];
        g_task[ti].Queue[qi + 1] := tmp;
        o_swap_count := o_swap_count + 1;
      END_IF;
    END_FOR;
  END_IF;
END_FOR;

(* ================================================================
   PHASE 1: Station-based restrictions from g_avoid_status
   For each active transporter, search stations near current_station
   and restrict x_min/x_max based on avoid_status 1 (pass) and 2 (block).
   ================================================================ *)
FOR i := 1 TO MAX_Transporters DO
  IF NOT g_transporter[i].IsActive THEN
    CONTINUE;
  END_IF;

  min_x := g_cfg[i].DrivePosMin;
  max_x := g_cfg[i].DrivePosMax;
  current_x := g_transporter[i].XPosition;
  avoid_dist := g_cfg[i].AvoidanceWidth;

  (* If no limits configured, lock to current position *)
  IF (min_x < 1) OR (max_x < 1) THEN
    g_transporter[i].XMinDriveLimit := current_x;
    g_transporter[i].XMaxDriveLimit := current_x;
    CONTINUE;
  END_IF;

  has_left_s2 := FALSE;
  has_right_s2 := FALSE;
  left_s2_x := 0;
  right_s2_x := 0;

  (* --- Search downward (smaller station numbers) from current_station --- *)
  stn_num := g_transporter[i].CurrentStation - 1;
  WHILE stn_num >= MIN_StationIndex DO
    IF g_station[stn_num].TankId = 0 THEN
      stn_num := stn_num - 1;
      CONTINUE;
    END_IF;

    stn_x := g_station[stn_num].XPosition;
    IF stn_x < min_x THEN
      EXIT;
    END_IF;

    avoid_st := g_avoid_status[stn_num];

    (* AVOID_Passable: passable unless it is this transporter's target station *)
    IF avoid_st = AVOID_Passable THEN
      is_target := (stn_num = g_transporter[i].LiftStationTarget)
               OR  (stn_num = g_transporter[i].SinkStationTarget);
      IF is_target THEN
        IF current_x < stn_x THEN
          new_val := stn_x - avoid_dist;
          IF new_val < max_x THEN max_x := new_val; END_IF;
          right_s2_x := stn_x;
          has_right_s2 := TRUE;
        ELSE
          new_val := stn_x + avoid_dist;
          IF new_val > min_x THEN min_x := new_val; END_IF;
          left_s2_x := stn_x;
          has_left_s2 := TRUE;
        END_IF;
        EXIT;
      END_IF;
      (* else: passable, keep searching *)
    END_IF;

    (* AVOID_Block: hard block — transporter cannot cross *)
    IF avoid_st = AVOID_Block THEN
      IF current_x < stn_x THEN
        new_val := stn_x - avoid_dist;
        IF new_val < max_x THEN max_x := new_val; END_IF;
        right_s2_x := stn_x;
        has_right_s2 := TRUE;
      ELSE
        new_val := stn_x + avoid_dist;
        IF new_val > min_x THEN min_x := new_val; END_IF;
        left_s2_x := stn_x;
        has_left_s2 := TRUE;
      END_IF;
      EXIT;
    END_IF;

    stn_num := stn_num - 1;
  END_WHILE;

  (* --- Search upward (larger station numbers) from current_station --- *)
  stn_num := g_transporter[i].CurrentStation + 1;
  WHILE stn_num <= MAX_StationIndex DO
    IF g_station[stn_num].TankId = 0 THEN
      stn_num := stn_num + 1;
      CONTINUE;
    END_IF;

    stn_x := g_station[stn_num].XPosition;
    IF stn_x > max_x THEN
      EXIT;
    END_IF;

    avoid_st := g_avoid_status[stn_num];

    IF avoid_st = AVOID_Passable THEN
      is_target := (stn_num = g_transporter[i].LiftStationTarget)
               OR  (stn_num = g_transporter[i].SinkStationTarget);
      IF is_target THEN
        IF current_x < stn_x THEN
          new_val := stn_x - avoid_dist;
          IF new_val < max_x THEN max_x := new_val; END_IF;
          right_s2_x := stn_x;
          has_right_s2 := TRUE;
        ELSE
          new_val := stn_x + avoid_dist;
          IF new_val > min_x THEN min_x := new_val; END_IF;
          left_s2_x := stn_x;
          has_left_s2 := TRUE;
        END_IF;
        EXIT;
      END_IF;
    END_IF;

    IF avoid_st = AVOID_Block THEN
      IF current_x < stn_x THEN
        new_val := stn_x - avoid_dist;
        IF new_val < max_x THEN max_x := new_val; END_IF;
        right_s2_x := stn_x;
        has_right_s2 := TRUE;
      ELSE
        new_val := stn_x + avoid_dist;
        IF new_val > min_x THEN min_x := new_val; END_IF;
        left_s2_x := stn_x;
        has_left_s2 := TRUE;
      END_IF;
      EXIT;
    END_IF;

    stn_num := stn_num + 1;
  END_WHILE;

  (* Conflict resolution: trapped between two BLOCK stations *)
  IF (min_x >= max_x) AND has_left_s2 AND has_right_s2 THEN
    midpoint := (left_s2_x + right_s2_x) / 2;
    min_x := midpoint - 5;
    max_x := midpoint + 5;
  END_IF;

  g_transporter[i].XMinDriveLimit := min_x;
  g_transporter[i].XMaxDriveLimit := max_x;
END_FOR;

(* ================================================================
   STEP 2.0: Basic safety distance — current positions
   Every active transporter pushes neighbors away by x_avoid_mm.
   ================================================================ *)
FOR i := 1 TO MAX_Transporters DO
  IF NOT g_transporter[i].IsActive THEN
    CONTINUE;
  END_IF;

  current_x := g_transporter[i].XPosition;
  current_y := g_transporter[i].YPosition;
  avoid_dist := g_cfg[i].AvoidanceWidth;

  FOR j := 1 TO MAX_Transporters DO
    IF j = i THEN CONTINUE; END_IF;
    IF NOT g_transporter[j].IsActive THEN CONTINUE; END_IF;

    (* Skip transporters on different line (y-position check, matches JS Step 2.0) *)
    other_y := g_transporter[j].YPosition;
    IF ABS(other_y - current_y) >= 1 THEN CONTINUE; END_IF;

    other_x := g_transporter[j].XPosition;

    IF other_x > current_x THEN
      (* j is to the RIGHT of i — restrict j's x_min *)
      new_val := current_x + avoid_dist;
      IF new_val > g_transporter[j].XMinDriveLimit THEN
        g_transporter[j].XMinDriveLimit := new_val;
      END_IF;
    ELSIF other_x < current_x THEN
      (* j is to the LEFT of i — restrict j's x_max *)
      new_val := current_x - avoid_dist;
      IF new_val < g_transporter[j].XMaxDriveLimit THEN
        g_transporter[j].XMaxDriveLimit := new_val;
      END_IF;
    END_IF;
  END_FOR;
END_FOR;

(* ================================================================
   STEP 2.2: Priority-based collision avoidance
   ================================================================ *)

(* --- 2.2.1: Build sorted array of active transporters by x-position --- *)
n_active := 0;
FOR i := 1 TO MAX_Transporters DO
  IF g_transporter[i].IsActive THEN
    n_active := n_active + 1;
    w_idx[n_active] := i;
    w_xpos[n_active] := g_transporter[i].XPosition;
    w_phase[n_active] := g_transporter[i].Phase;
    w_status[n_active] := g_transporter[i].Status;
    w_ypos[n_active] := g_transporter[i].YPosition;
    w_target[n_active] := g_transporter[i].XFinalTarget;
    w_avoid[n_active] := g_cfg[i].AvoidanceWidth;
  END_IF;
END_FOR;

(* Selection sort by x-position (ascending) *)
FOR i := 1 TO n_active - 1 DO
  min_idx := i;
  FOR j := i + 1 TO n_active DO
    IF w_xpos[j] < w_xpos[min_idx] THEN
      min_idx := j;
    END_IF;
  END_FOR;
  IF min_idx <> i THEN
    tmp_int := w_idx[i];    w_idx[i] := w_idx[min_idx];    w_idx[min_idx] := tmp_int;
    tmp_dint := w_xpos[i];  w_xpos[i] := w_xpos[min_idx];  w_xpos[min_idx] := tmp_dint;
    tmp_int := w_phase[i];  w_phase[i] := w_phase[min_idx]; w_phase[min_idx] := tmp_int;
    tmp_int := w_status[i]; w_status[i] := w_status[min_idx]; w_status[min_idx] := tmp_int;
    tmp_dint := w_ypos[i];  w_ypos[i] := w_ypos[min_idx];  w_ypos[min_idx] := tmp_dint;
    tmp_dint := w_target[i]; w_target[i] := w_target[min_idx]; w_target[min_idx] := tmp_dint;
    tmp_dint := w_avoid[i];  w_avoid[i] := w_avoid[min_idx];  w_avoid[min_idx] := tmp_dint;
  END_IF;
END_FOR;

(* --- 2.2.2: Calculate canEvade and priority --- *)
FOR i := 1 TO n_active DO
  k := w_idx[i];

  (* canEvade rules (from JS specification):
     RULE 1: status < 3 → not in automatic mode, cannot evade
     RULE 2: status = 4 AND phase ∈ {2,4} → Z-movement, cannot evade
     RULE 3: working area too small → cannot evade *)
  w_can_evade[i] := TRUE;
  IF w_status[i] < 3 THEN
    w_can_evade[i] := FALSE;
  END_IF;
  IF (w_status[i] = 4) AND ((w_phase[i] = 2) OR (w_phase[i] = 4)) THEN
    w_can_evade[i] := FALSE;
  END_IF;
  work_area := g_transporter[k].XMaxDriveLimit - g_transporter[k].XMinDriveLimit;
  IF work_area < MIN_WorkingArea THEN
    w_can_evade[i] := FALSE;
  END_IF;

  w_priority[i] := TWA_CalcPriority(
    i_phase := w_phase[i],
    i_can_evade := w_can_evade[i],
    i_x_pos := w_xpos[i],
    i_x_target := w_target[i]
  );
END_FOR;

(* Skip Steps 2.2.3-2.2.5 if fewer than 2 active transporters *)
IF n_active >= 2 THEN

  (* --- 2.2.3: Priority restrictions (higher priority → lower priority) --- *)
  FOR i := 1 TO n_active DO
    (* Skip idle transporters — they don't set priority restrictions *)
    IF w_phase[i] = 0 THEN CONTINUE; END_IF;

    FOR j := 1 TO n_active DO
      IF i = j THEN CONTINUE; END_IF;
      (* Skip transporters on different line *)
      IF ABS(w_ypos[i] - w_ypos[j]) >= 1 THEN CONTINUE; END_IF;

      (* Determine if i has higher priority than j *)
      a_wins := FALSE;
      IF w_priority[i] > w_priority[j] THEN
        a_wins := TRUE;
      ELSIF (w_priority[i] = w_priority[j]) AND (w_idx[i] < w_idx[j]) THEN
        a_wins := TRUE;
      END_IF;

      IF NOT a_wins THEN CONTINUE; END_IF;

      (* Higher priority transporter uses target for phase 1/3, else current pos *)
      IF (w_phase[i] = 1) OR (w_phase[i] = 3) THEN
        restrict_x := w_target[i];
      ELSE
        restrict_x := w_xpos[i];
      END_IF;

      k := w_idx[j];
      cur_min := g_transporter[k].XMinDriveLimit;
      cur_max := g_transporter[k].XMaxDriveLimit;

      IF w_xpos[i] < w_xpos[j] THEN
        (* i is LEFT, j is RIGHT — i sets j's x_min *)
        (* Count same-line transporters between i and j *)
        between := 0;
        FOR stn_num := i + 1 TO j - 1 DO
          IF ABS(w_ypos[stn_num] - w_ypos[i]) < 1 THEN between := between + 1; END_IF;
        END_FOR;
        chain_ofs := w_avoid[i] + INT_TO_DINT(between) * (MIN_WorkingArea + w_avoid[i]);
        new_val := restrict_x + chain_ofs;

        IF new_val > cur_min THEN
          IF new_val <= (cur_max - MIN_WorkingArea) THEN
            g_transporter[k].XMinDriveLimit := new_val;
          ELSE
            adjusted := cur_max - MIN_WorkingArea;
            IF adjusted > cur_min THEN
              g_transporter[k].XMinDriveLimit := adjusted;
            END_IF;
          END_IF;
        END_IF;

      ELSIF w_xpos[i] > w_xpos[j] THEN
        (* i is RIGHT, j is LEFT — i sets j's x_max *)
        (* Count same-line transporters between j and i *)
        between := 0;
        FOR stn_num := j + 1 TO i - 1 DO
          IF ABS(w_ypos[stn_num] - w_ypos[i]) < 1 THEN between := between + 1; END_IF;
        END_FOR;
        chain_ofs := w_avoid[i] + INT_TO_DINT(between) * (MIN_WorkingArea + w_avoid[i]);
        new_val := restrict_x - chain_ofs;

        IF new_val < cur_max THEN
          IF new_val >= (cur_min + MIN_WorkingArea) THEN
            g_transporter[k].XMaxDriveLimit := new_val;
          ELSE
            adjusted := cur_min + MIN_WorkingArea;
            IF adjusted < cur_max THEN
              g_transporter[k].XMaxDriveLimit := adjusted;
            END_IF;
          END_IF;
        END_IF;
      END_IF;
    END_FOR;
  END_FOR;

  (* --- 2.2.4: Bidirectional safety (both moving same direction) --- *)
  FOR i := 1 TO n_active - 1 DO
    j := i + 1;
    (* i = left (smaller x), j = right (larger x) — sorted array *)

    (* Skip if not on same line *)
    IF ABS(w_ypos[i] - w_ypos[j]) >= 1 THEN CONTINUE; END_IF;

    left_right := ((w_phase[i] = 1) OR (w_phase[i] = 3)) AND (w_target[i] > w_xpos[i]);
    right_right := ((w_phase[j] = 1) OR (w_phase[j] = 3)) AND (w_target[j] > w_xpos[j]);
    left_left := ((w_phase[i] = 1) OR (w_phase[i] = 3)) AND (w_target[i] < w_xpos[i]);
    right_left := ((w_phase[j] = 1) OR (w_phase[j] = 3)) AND (w_target[j] < w_xpos[j]);

    IF left_right AND right_right THEN
      (* Both moving right — left chasing right *)
      safety_val := w_xpos[i] + w_avoid[i];
      k := w_idx[j];
      IF safety_val > g_transporter[k].XMinDriveLimit THEN
        g_transporter[k].XMinDriveLimit := safety_val;
      END_IF;
    END_IF;

    IF left_left AND right_left THEN
      (* Both moving left — right chasing left *)
      safety_val := w_xpos[j] - w_avoid[j];
      k := w_idx[i];
      IF safety_val < g_transporter[k].XMaxDriveLimit THEN
        g_transporter[k].XMaxDriveLimit := safety_val;
      END_IF;
    END_IF;
  END_FOR;

  (* --- 2.2.5: Validate limits (trap detection) --- *)
  FOR i := 1 TO n_active DO
    k := w_idx[i];
    IF g_transporter[k].XMinDriveLimit > g_transporter[k].XMaxDriveLimit THEN
      (* Trapped — lock in place *)
      g_transporter[k].XMinDriveLimit := g_transporter[k].XPosition;
      g_transporter[k].XMaxDriveLimit := g_transporter[k].XPosition;
    END_IF;
  END_FOR;

END_IF;  (* n_active >= 2 *)

(* ============================================================
   CONFIG UPLOAD HANDLER
   Gateway writes station data one at a time via Modbus IW regs.
   Sequence number change triggers processing.
   cmd=1: write_station  cmd=2: init  cmd=3: clear_all
   ============================================================ *)
IF iw_cfg_seq <> last_cfg_seq THEN
  last_cfg_seq := iw_cfg_seq;

  IF iw_cfg_cmd = 3 THEN
    (* --- Clear all config data --- *)
    clear_cfg();
    init_done := FALSE;
    g_station_count := 0;

  ELSIF iw_cfg_cmd = 1 THEN
    (* --- Write one station to g_station array --- *)
    IF (iw_cfg_param >= MIN_StationIndex) AND (iw_cfg_param <= MAX_StationIndex) THEN
      g_station[iw_cfg_param].TankId       := iw_cfg_d0;
      g_station[iw_cfg_param].XPosition    := INT_TO_DINT(iw_cfg_d1);
      g_station[iw_cfg_param].YPosition    := INT_TO_DINT(iw_cfg_d2);
      g_station[iw_cfg_param].ZPosition    := INT_TO_DINT(iw_cfg_d3);
      g_station[iw_cfg_param].StationType     := iw_cfg_d4;
      g_station[iw_cfg_param].DryWet            := iw_cfg_d7;
      g_station[iw_cfg_param].DrippingTime := iw_cfg_d5;
      g_station[iw_cfg_param].DeviceDelay  := iw_cfg_d6;
    END_IF;

  ELSIF iw_cfg_cmd = 4 THEN
    (* --- Write transporter physics page 1 --- *)
    (* param = transporter_id (1..3)
       d0 = x_min_limit mm      d1 = x_max_limit mm
       d2 = x_accel_s × 10      d3 = x_decel_s × 10
       d4 = x_max_mm_s           d5 = z_total_mm
       d6 = AvoidanceWidth/CollisionWidth *)
    j := iw_cfg_param;
    IF (j >= 1) AND (j <= 3) THEN
      g_cfg[j].DrivePosMin          := INT_TO_DINT(iw_cfg_d0);
      g_cfg[j].DrivePosMax          := INT_TO_DINT(iw_cfg_d1);
      g_cfg[j].Acceleration_X     := INT_TO_DINT(iw_cfg_d2);
      g_cfg[j].Deceleration_X     := INT_TO_DINT(iw_cfg_d3);
      g_cfg[j].SpeedMax_X    := INT_TO_DINT(iw_cfg_d4);
      g_cfg[j].ZPosDown    := INT_TO_DINT(iw_cfg_d5);
      g_cfg[j].AvoidanceWidth          := INT_TO_DINT(iw_cfg_d6);
      g_cfg[j].CollisionWidth           := INT_TO_DINT(iw_cfg_d6);
    END_IF;

  ELSIF iw_cfg_cmd = 5 THEN
    (* --- Write transporter physics page 2 --- *)
    (* param = transporter_id (1..3)
       d0 = z_slow_dry_mm        d1 = z_slow_wet_mm
       d2 = ZPosSlowEnd        d3 = z_slow_mm_s
       d4 = z_fast_mm_s          d5 = DripTrayDelay × 10
       d6 = (reserved) *)
    j := iw_cfg_param;
    IF (j >= 1) AND (j <= 3) THEN
      g_cfg[j].ZPosSlowUp := INT_TO_DINT(iw_cfg_d0);
      g_cfg[j].ZPosSlowDown := INT_TO_DINT(iw_cfg_d1);
      g_cfg[j].ZPosSlowEnd := INT_TO_DINT(iw_cfg_d2);
      g_cfg[j].SpeedLiftSlow_Z   := INT_TO_DINT(iw_cfg_d3);
      g_cfg[j].SpeedLiftFast_Z   := INT_TO_DINT(iw_cfg_d4);
      g_cfg[j].DripTrayDelay  := iw_cfg_d5;
    END_IF;

  ELSIF iw_cfg_cmd = 6 THEN
    (* --- Write transporter task area --- *)
    (* param = transporter_id × 10 + area_index
       e.g. 11 = transporter 1 area 1, 23 = transporter 2 area 3
       d0 = min_lift   d1 = max_lift
       d2 = min_sink   d3 = max_sink *)
    j := iw_cfg_param / 10;
    k := iw_cfg_param MOD 10;
    IF (j >= 1) AND (j <= 3) AND (k >= 1) AND (k <= 4) THEN
      g_cfg[j].TaskArea[k].MinLift := iw_cfg_d0;
      g_cfg[j].TaskArea[k].MaxLift := iw_cfg_d1;
      g_cfg[j].TaskArea[k].MinSink := iw_cfg_d2;
      g_cfg[j].TaskArea[k].MaxSink := iw_cfg_d3;
    END_IF;

  ELSIF iw_cfg_cmd = 7 THEN
    (* --- Calibration plan for one transporter --- *)
    (* param = transporter_id (1..3)
       d0 = wet_station   d1 = dry_station *)
    j := iw_cfg_param;
    IF (j >= 1) AND (j <= 3) THEN
      g_cal[j].WetStation := iw_cfg_d0;
      g_cal[j].DryStation := iw_cfg_d1;
    END_IF;

  ELSIF iw_cfg_cmd = 8 THEN
    (* --- Calibration control --- *)
    (* param: 1=start, 2=calculate, 3=abort *)
    cal_cmd := iw_cfg_param;

  ELSIF iw_cfg_cmd = 9 THEN
    (* --- Write NTT primary stations --- *)
    (* param = transporter_id × 100 + target_code × 10 + station_count
       e.g. 112 = transporter 1, TO_LOADING(1), 2 stations
       d0..d4 = stations[1..5] *)
    j := iw_cfg_param / 100;             (* transporter *)
    k := (iw_cfg_param / 10) MOD 10;     (* target code 1..8 *)
    i := iw_cfg_param MOD 10;            (* station_count *)
    IF (j >= 1) AND (j <= MAX_Transporters) AND (k >= 1) AND (k <= 8) AND (i >= 0) AND (i <= MAX_STATIONS_PER_STEP) THEN
      g_ntt[j].Target[k].StationCount := i;
      g_ntt[j].Target[k].Stations[1] := iw_cfg_d0;
      g_ntt[j].Target[k].Stations[2] := iw_cfg_d1;
      g_ntt[j].Target[k].Stations[3] := iw_cfg_d2;
      g_ntt[j].Target[k].Stations[4] := iw_cfg_d3;
      g_ntt[j].Target[k].Stations[5] := iw_cfg_d4;
    END_IF;

  ELSIF iw_cfg_cmd = 10 THEN
    (* --- Write NTT fallback stations --- *)
    (* param = transporter_id × 100 + target_code × 10 + fallback_count
       d0..d4 = fallback_stations[1..5] *)
    j := iw_cfg_param / 100;             (* transporter *)
    k := (iw_cfg_param / 10) MOD 10;     (* target code 1..8 *)
    i := iw_cfg_param MOD 10;            (* fallback_count *)
    IF (j >= 1) AND (j <= MAX_Transporters) AND (k >= 1) AND (k <= 8) AND (i >= 0) AND (i <= MAX_STATIONS_PER_STEP) THEN
      g_ntt[j].Target[k].FallbackCount := i;
      g_ntt[j].Target[k].FallbackStations[1] := iw_cfg_d0;
      g_ntt[j].Target[k].FallbackStations[2] := iw_cfg_d1;
      g_ntt[j].Target[k].FallbackStations[3] := iw_cfg_d2;
      g_ntt[j].Target[k].FallbackStations[4] := iw_cfg_d3;
      g_ntt[j].Target[k].FallbackStations[5] := iw_cfg_d4;
    END_IF;

  ELSIF iw_cfg_cmd = 11 THEN
    (* --- Load kinematic params for one transporter into g_cal --- *)
    (* param = tid (1..3)
       d0 = lift_wet_s × 100   d1 = sink_wet_s × 100
       d2 = lift_dry_s × 100   d3 = sink_dry_s × 100
       d4 = x_accel_s × 100    d5 = x_decel_s × 100
       d6 = x_max_mm_s (integer, mm/s) *)
    j := iw_cfg_param;
    IF (j >= 1) AND (j <= 3) THEN
      g_cal[j].LiftWetTime := iw_cfg_d0 / 10;
      g_cal[j].SinkWetTime := iw_cfg_d1 / 10;
      g_cal[j].LiftDryTime := iw_cfg_d2 / 10;
      g_cal[j].SinkDryTime := iw_cfg_d3 / 10;
      g_cal[j].XAccelTime  := iw_cfg_d4 / 10;
      g_cal[j].XDecelTime  := iw_cfg_d5 / 10;
      g_cal[j].XMaxSpeed := INT_TO_DINT(iw_cfg_d6);
    END_IF;

  ELSIF iw_cfg_cmd = 12 THEN
    (* --- Compute g_move from loaded g_cal kinematic params --- *)
    (* No params needed — computes for all transporters with valid g_cal *)
    cal_load_run := TRUE;

  ELSIF iw_cfg_cmd = 2 THEN
    (* --- Finish init: all config uploaded, init transporter states --- *)
    g_station_count := iw_cfg_param;

    FOR i := 1 TO MAX_Transporters DO
      (* Active if task_area[1] has non-zero stations *)
      IF g_cfg[i].TaskArea[1].MinLift > 0 THEN
        g_transporter[i].IsActive := TRUE;
        g_transporter[i].Status := 3;  (* auto_idle *)
      ELSE
        g_transporter[i].IsActive := FALSE;
        g_transporter[i].Status := 0;  (* not_used *)
      END_IF;
      g_transporter[i].Phase := 0;
      g_sim_trans[i].ZStage := 0;
      g_sim_trans[i].XVelocity := 0;
      g_sim_trans[i].ZTimer := 0.0;
      g_transporter[i].XMinDriveLimit := g_cfg[i].DrivePosMin;
      g_transporter[i].XMaxDriveLimit := g_cfg[i].DrivePosMax;

      (* Start position: at own area minimum, z=0 *)
      g_transporter[i].XPosition := g_cfg[i].DrivePosMin;
      g_transporter[i].ZPosition := 0;
      g_transporter[i].CurrentStation := 0;
    END_FOR;

    init_done := TRUE;

    (* Init event queue *)
    g_event.Head := 1;
    g_event.NextSeq := 1;
    g_event.Count := 0;
  END_IF;
END_IF;

(* ============================================================
   MAIN TRANSPORT CYCLE — only runs when init_done
   ============================================================ *)
IF init_done THEN

(* ── Compute g_move from loaded kinematic params (one-shot) ── *)
calc_move(i_run := cal_load_run);
IF cal_load_run THEN
  cal_load_run := FALSE;
END_IF;

(* Calculate transporter working areas (X-limits) every cycle *)
twa_calc();

(* ── Production queue sync from gateway ── *)
g_production_queue := iw_production_queue;

(* ── Unix time maintenance ── *)
(* PLC keeps g_time_s by incrementing +1 every 50 cycles (50 × 20 ms = 1 s).
   Gateway periodically writes reference unix seconds to QW160/QW161.
   When PLC detects the register values changed → sync to gateway time. *)
IF iw_time_hi <> last_sync_hi OR iw_time_lo <> last_sync_lo THEN
  (* Gateway wrote new reference time — sync *)
  time_hi := INT_TO_LINT(iw_time_hi);
  IF time_hi < LINT#0 THEN
    time_hi := time_hi + LINT#65536;
  END_IF;
  time_lo := INT_TO_LINT(iw_time_lo);
  IF time_lo < LINT#0 THEN
    time_lo := time_lo + LINT#65536;
  END_IF;
  g_time_s := time_hi * LINT#65536 + time_lo;
  last_sync_hi := iw_time_hi;
  last_sync_lo := iw_time_lo;
  time_cycle_cnt := 0;
ELSE
  (* Self-increment: +1 second every 50 cycles (50 × 20 ms) *)
  time_cycle_cnt := time_cycle_cnt + 1;
  IF time_cycle_cnt >= 50 THEN
    g_time_s := g_time_s + LINT#1;
    time_cycle_cnt := 0;
  END_IF;
END_IF;

(* ── Execute transporter tasks (physics simulation) ── *)
run_tasks(i_run := init_done);

(* ── Calibration FB — issues test tasks, measures parameters ── *)
calibrate(i_run := init_done, i_cmd := cal_cmd);
cal_cmd := 0;   (* consumed after one cycle *)
g_cal_active := calibrate.o_active;

END_IF;  (* init_done *)

(* ── Main Scheduler (TSK + DEP alternating cycles) ──
   MUST run outside init_done block so that when init_done=FALSE
   (during RESET), MainScheduler's i_run=FALSE path executes,
   properly resetting internal state of both TSK and DEP FBs. *)
main_sched(i_run := init_done, i_time_s := g_time_s);

(* ── Event queue — always runs, not gated by init_done ── *)
evt_queue();

(* ============================================================
   UNIT WRITE HANDLER — gateway writes one unit at a time
   ============================================================ *)
